-- Replace the legacy all-in-one Chapter 6400 course for new enrollment with
-- independently assignable, version-scoped courses. Historical versions,
-- assignments, progress, certificates, and training records remain intact.
--
-- Regulatory basis (official Commonwealth sources):
--   * 55 Pa. Code Section 6400.52 - annual training hours, audiences, and topics.
--   * 55 Pa. Code Sections 6400.46 and 6400.50 - emergency training and records.
--   * 55 Pa. Code Sections 6400.186 and 6400.196 - individual-plan implementation
--     and person-specific behavior-support training.
--   * 55 Pa. Code Section 6400.169 - Department-approved medication training.
--   * DHS Chapter 6400 Regulatory Compliance Guide, February 3, 2020 edition.
--
-- The web-deliverable curriculum below supplies 20 designed hours of eligible
-- content, followed by two two-hour person-specific courses. The schema does not
-- yet model the Section 6400.52 direct-service versus other-staff audience, so
-- every GH crosswalk is verified-only: the home must confirm role, applicability,
-- and evidence before applying hours. Fire and first-aid/CPR are also separate
-- verified evidence and never self-certify the required trainer.

do $migration$
declare
  v_catalog jsonb := $catalog$
[
  {
    "catalog_code": "PA-GH-6400-PCP-FOUNDATIONS",
    "title": "Person-Centered Practice and Everyday Choice",
    "description": "A comprehensive Chapter 6400 annual-training course on person-centered practice, dignity, supported choice, and translating what matters to a person into daily support. After the home verifies audience, applicability, and evidence, the course may contribute two designed hours; it is not professional continuing education approval.",
    "duration_minutes": 120,
    "credit_hours": 2.00,
    "topic_code": "6400.52.C1.PCP_FOUNDATIONS",
    "direct_mode": "verified_only",
    "other_mode": "verified_only",
    "citation_note": "55 Pa. Code Section 6400.52(c)(1): annual training must encompass person-centered practices, community integration, individual choice, and support for relationships. DHS guidance permits accurate web delivery for this topic.",
    "objectives_minutes": 5,
    "objectives": [
      "Distinguish person-centered support from schedule-centered or staff-centered routines.",
      "Use informed choice, supported decision-making, and positive risk management in ordinary work.",
      "Convert a person's preferences, communication, culture, strengths, and goals into observable staff actions.",
      "Recognize when convenience, assumptions, or overprotection are displacing the person's voice."
    ],
    "lessons": [
      {
        "title": "Start With the Person, Not the Program",
        "estimated_minutes": 18,
        "activity_type": "guided_instruction",
        "content": "Person-centered practice begins with a simple discipline: learn who the person is before deciding what support should look like. A diagnosis, risk label, staffing ratio, or list of deficits never describes a whole person. Staff need to know what the person values, how the person communicates yes and no, which relationships matter, what a good day looks like, what causes distress, and which abilities can be strengthened.\n\nCompare two approaches. A program-centered approach starts with the shift checklist and moves everyone through the same routine. A person-centered approach starts with each person's Individual Plan, current preferences, health and safety needs, and chosen rhythm. Required supports still occur, but staff offer meaningful choices about timing, sequence, method, location, and participation.\n\nGuided practice: select one routine such as waking, meals, personal care, medication, transportation, or bedtime. Identify the nonnegotiable health or safety requirement, then list at least four parts the person can control. Check whether your current words and actions make those choices real rather than merely ceremonial."
      },
      {
        "title": "Choice, Consent, and Supported Decision-Making",
        "estimated_minutes": 18,
        "activity_type": "guided_instruction",
        "content": "Choice is not limited to selecting between two staff-preferred options. Staff provide understandable information, allow processing time, use the person's communication method, explain likely consequences without pressure, and respect a decision unless a lawful, plan-based limitation applies. A person may need pictures, objects, demonstrations, plain language, interpreters, communication technology, or support from a trusted person. Support should help the person decide; it should not transfer the decision to staff.\n\nConsent is ongoing. Agreement yesterday does not automatically authorize an activity today. Watch for words, signs, gestures, movement, facial expression, or behavior that communicates hesitation or refusal. Pause, clarify, and document important changes. Never use access to food, relationships, possessions, community activities, or routine care as leverage.\n\nGuided practice: rewrite three directive statements into supported-choice questions. For each, identify what information the person needs, how you will verify understanding, how the person communicates refusal, and what you will do if the choice creates a significant risk."
      },
      {
        "title": "Strengths, Preferences, Culture, and Communication",
        "estimated_minutes": 18,
        "activity_type": "guided_instruction",
        "content": "Person-centered support is specific. A note that someone likes music is less useful than knowing which music, at what volume, with whom, and whether it calms or energizes the person. Effective staff notice abilities, successful routines, sensory preferences, cultural and religious practices, gender identity, food traditions, relationships, and preferred ways of receiving help. They avoid treating a communication difference as lack of understanding.\n\nUse respectful observation and direct inquiry. Ask the person first whenever possible, then consult the current assessment, Individual Plan, communication profile, family or chosen supporters, and staff who know the person well. Record new information factually and route it to the person responsible for plan updates. Do not place stereotypes, casual judgments, or private gossip in records.\n\nGuided practice: create a one-page good-support profile using only information authorized for staff use. Include strengths, communication signals, important relationships, preferred routines, stress indicators, helpful responses, and what staff must never assume. Compare it with the current plan and report discrepancies."
      },
      {
        "title": "Positive Risk, Duty of Care, and the Least Intrusive Support",
        "estimated_minutes": 18,
        "activity_type": "guided_instruction",
        "content": "People have the right to make choices and accept ordinary risk. Staff also have a duty to implement assessed safeguards. Good practice avoids both neglect and unnecessary control. Begin by defining the actual risk, its likelihood and severity, the person's understanding, and the least intrusive support that could reduce danger while preserving the goal. Seek adaptive equipment, skill teaching, environmental changes, additional information, or gradual practice before restricting a choice.\n\nA limitation cannot be invented during a shift because staff feel uncomfortable. Significant rights modifications belong in the Individual Plan and must follow Chapter 6400 requirements. During an urgent danger, take proportionate protective action, notify the appropriate person, and document what happened; do not turn an emergency response into an unwritten permanent rule.\n\nGuided practice: analyze a community activity that staff consider risky. Separate facts from predictions, name the person's desired outcome, propose three less restrictive safeguards, and identify who must review any proposed plan change."
      },
      {
        "title": "Make Person-Centered Practice Visible",
        "estimated_minutes": 15,
        "activity_type": "guided_instruction",
        "content": "Survey-ready person-centered practice is visible in ordinary interactions and records. Staff knock and seek permission, speak to the person rather than around the person, offer time to respond, protect privacy, use age-respectful language, and support access to personal belongings and community life. Notes connect staff support to the person's goals and response instead of describing only tasks completed.\n\nWatch for drift: everyone eating, bathing, shopping, or going to bed at the same time; activities selected for staffing convenience; choices offered after decisions are already made; goals copied forward without evidence; or behavior interpreted without asking what the person is communicating. Raise these patterns through supervision and quality improvement rather than normalizing them.\n\nGuided practice: observe one hour of a typical shift. Tally genuine choices offered, the person's responses, instances in which staff waited or adapted, and any convenience-driven restriction. Choose one measurable improvement for the next shift and identify how it will be documented."
      }
    ],
    "scenarios": [
      {
        "title": "Applied Scenario: The Late Breakfast",
        "estimated_minutes": 8,
        "activity_type": "applied_scenario",
        "content": "Jordan prefers breakfast at 10:00 a.m., while the house schedule lists breakfast at 8:00. A coworker says everyone must eat together because cleanup is easier. Work through the decision: identify Jordan's right and preference, any actual health or medication timing concern, choices staff can offer, how coverage and cleanup can be adjusted, and what must be reported if the written plan conflicts with Jordan's current preference. The defensible response preserves Jordan's choice unless an assessed requirement calls for a different approach and documents any needed plan review."
      },
      {
        "title": "Applied Scenario: Choice With Real Risk",
        "estimated_minutes": 8,
        "activity_type": "applied_scenario",
        "content": "Maya wants to walk to a nearby store alone. She has previously become disoriented on unfamiliar routes. Do not answer only yes or no. Identify Maya's goal, review the current assessment and plan, ask how she understands the route and emergency options, and design graduated supports such as route practice, navigation technology, check-ins, or meeting a known person. Explain which staff may approve routine supports and when the team must consider a formal plan revision."
      }
    ],
    "source_minutes": 4,
    "source_content": "Primary authority: 55 Pa. Code Section 6400.52(c)(1), annual training in person-centered practices, community integration, individual choice, and supporting relationships; Section 6400.32, rights of the individual; and the Pennsylvania DHS Chapter 6400 Regulatory Compliance Guide discussion of Sections 6400.51-52. Review the current official text at https://www.pacodeandbulletin.gov/secure/pacode/data/055/chapter6400/s6400.52.html and https://www.pacodeandbulletin.gov/secure/pacode/data/055/chapter6400/s6400.32.html. Facility policy and the current Individual Plan control person-specific procedures.",
    "quiz_minutes": 8,
    "questions": [
      {"text": "Which action best demonstrates person-centered practice?", "explanation": "Person-centered support preserves required safeguards while giving the person meaningful control over timing, method, and participation.", "answers": [{"text": "Require everyone to follow one house schedule", "correct": false}, {"text": "Offer meaningful choices within assessed health and safety needs", "correct": true}, {"text": "Let staff decide because they are responsible", "correct": false}, {"text": "Offer choices only when they do not affect the shift", "correct": false}]},
      {"text": "What is the first source for learning a person's current preference when communication is possible?", "explanation": "Staff should ask and observe the person directly, using the person's communication method, before relying on others' assumptions.", "answers": [{"text":"The person, using their preferred and accessible communication method","correct":true}, {"text": "A former staff member", "correct": false}, {"text": "The house schedule", "correct": false}, {"text": "A diagnosis list", "correct": false}]},
      {"text": "Supported decision-making means:", "explanation": "Supported decision-making helps a person understand options and communicate a decision without transferring decision authority to staff.", "answers": [{"text": "Staff select the safest option", "correct": false}, {"text": "Family always makes the decision", "correct": false}, {"text": "The person receives accessible information and support to decide", "correct": true}, {"text": "Only two staff-approved options may be offered", "correct": false}]},
      {"text": "A person refuses an activity they accepted yesterday. What should staff do first?", "explanation": "Consent is ongoing; staff should pause, clarify the person's communication, and follow the current plan rather than assuming past consent continues.", "answers": [{"text": "Require participation because consent was already given", "correct": false}, {"text": "Remove another privilege", "correct": false}, {"text": "Pause and clarify the current refusal", "correct": true}, {"text": "Document noncompliance without speaking to the person", "correct": false}]},
      {"text": "When a chosen activity presents risk, the best initial approach is to:", "explanation": "Positive risk management defines the actual risk and seeks the least intrusive support that preserves the person's goal.", "answers": [{"text": "Ban the activity immediately", "correct": false}, {"text": "Honor the choice without discussing risk or planning any support", "correct": false}, {"text": "Identify the actual risk and try less intrusive safeguards", "correct": true}, {"text": "Let each shift create its own rule", "correct": false}]},
      {"text": "Which note is most person-centered?", "explanation": "A useful note connects support to the person's goal, choice, participation, and response rather than listing staff tasks alone.", "answers": [{"text": "Completed all shift duties", "correct": false}, {"text": "Took residents shopping", "correct": false}, {"text": "Jordan chose the market, used his picture list, and selected three items with one prompt", "correct": true}, {"text": "Jordan was good today", "correct": false}]},
      {"text": "An unwritten permanent restriction may be created by:", "explanation": "Staff may take proportionate action during an immediate danger, but an ongoing rights modification must follow the Individual Plan process.", "answers": [{"text": "Any staff member who feels concerned", "correct": false}, {"text": "A majority vote at shift change", "correct": false}, {"text": "No one; ongoing modifications require the proper plan process", "correct": true}, {"text": "A coworker with seniority", "correct": false}]},
      {"text": "Which pattern is a warning that practice has become staff-centered?", "explanation": "Uniform routines imposed for staff convenience can displace individual choice and should be reviewed.", "answers": [{"text": "Different bedtime routines based on preference", "correct": false}, {"text": "Everyone follows the same routine because it is easier to staff", "correct": true}, {"text": "Staff use each person's communication system", "correct": false}, {"text": "Plans are updated when preferences change", "correct": false}]}
    ]
  },
  {
    "catalog_code": "PA-GH-6400-COMMUNITY-RELATIONSHIPS",
    "title": "Community Integration and Supporting Relationships",
    "description": "A comprehensive Chapter 6400 course on belonging, ordinary community participation, relationship support, transportation planning, and removing program-created barriers. After the home verifies audience, applicability, and evidence, the course may contribute two designed annual-training hours.",
    "duration_minutes": 120,
    "credit_hours": 2.00,
    "topic_code": "6400.52.C1.COMMUNITY_RELATIONSHIPS",
    "direct_mode": "verified_only",
    "other_mode": "verified_only",
    "citation_note": "55 Pa. Code Section 6400.52(c)(1): annual training must encompass community integration, individual choice, and supporting individuals to develop and maintain relationships.",
    "objectives_minutes": 5,
    "objectives": ["Distinguish community presence from genuine participation and belonging.", "Plan individualized activities around interests, relationships, accessibility, and informed choice.", "Support contact, privacy, and boundaries in family, friendship, romantic, and community relationships.", "Identify and remove transportation, staffing, communication, financial, and attitudinal barriers."],
    "lessons": [
      {"title": "From Community Presence to Belonging", "estimated_minutes": 18, "activity_type": "guided_instruction", "content": "Being physically present in a public place is not the same as being included. Integration means using the same community places as other people, making choices about where and with whom to participate, developing familiar roles, and having opportunities for reciprocal relationships. A van trip in which a group watches from the edge may provide recreation but little belonging. A person who becomes a known customer, volunteer, club member, neighbor, student, worship participant, or teammate has a community role.\n\nBegin with the person's interests and desired relationships, not a rotating activity calendar. Learn what the person wants to try, what past experiences were positive or harmful, what sensory or accessibility supports are needed, and how much staff presence the person prefers. Avoid grouping people solely because they share a home or disability.\n\nGuided practice: take one routine group outing and redesign it as individualized participation. Identify the person's chosen role, natural interactions that could develop, transportation, cost, communication support, risk safeguards, and how staff will fade into the background when safe."},
      {"title": "Discovery and Informed Community Choice", "estimated_minutes": 18, "activity_type": "guided_instruction", "content": "People cannot choose from options they have never encountered. Discovery introduces possibilities without pressuring participation. Staff can use conversations, photos, short visits, demonstrations, community calendars, peer stories, and trial experiences. Offer options that reflect the person's age, culture, interests, energy, and preferred social setting. Include free and low-cost opportunities, not only provider-organized events.\n\nPreparation should make choice informed: explain location, duration, cost, transportation, expected environment, who will attend, accessibility, and what the person can do if they want to leave. Afterward, ask what the person enjoyed, disliked, or wants changed. A refusal is information, not failure.\n\nGuided practice: design a three-step discovery process for a new interest. Include an accessible preview, a low-pressure trial, a debrief using the person's communication method, and a record of the person's response for future planning."},
      {"title": "Relationships, Privacy, and Safe Support", "estimated_minutes": 18, "activity_type": "guided_instruction", "content": "Chapter 6400 training expressly includes supporting relationships. Staff should help people maintain family ties, friendships, romantic relationships, faith connections, neighbors, coworkers, and chosen supporters unless a lawful plan provision says otherwise. Support may include private access to phone or electronic communication, transportation, remembering important dates, hosting visitors, learning social skills, or resolving logistical barriers.\n\nSupport does not mean monitoring every conversation or selecting friends. Protect privacy and confidentiality. Teach boundaries, consent, internet safety, and ways to seek help in an age-respectful manner. Respond to risk with education and proportionate safeguards, not blanket isolation. Staff must never exploit, borrow from, socialize secretly with, or create dependency in a professional relationship.\n\nGuided practice: map one person's important relationships with authorization. Identify which connections the person wants to strengthen, what obstacle exists, what staff support is requested, and how to preserve privacy and autonomy."},
      {"title": "Transportation, Money, Communication, and Access", "estimated_minutes": 18, "activity_type": "guided_instruction", "content": "Many failed community goals are actually access failures. A person may need accessible transportation, route training, mobility support, spending-plan assistance, interpretation, communication technology, sensory accommodations, medication timing, meal planning, or staff trained in an individual-specific health procedure. Identify barriers early and assign responsibility rather than repeatedly documenting that the person could not attend.\n\nUse the least segregating reliable option. Explore walking, public transit, paratransit, rides with chosen supporters, taxis or ride services when safe and authorized, and provider transportation. Protect the person's funds: explain costs, obtain consent, keep required records, and never make purchases for staff convenience.\n\nGuided practice: select one missed opportunity and perform a barrier analysis. Sort obstacles into transportation, money, accessibility, communication, scheduling, health support, staffing, and attitude. Create a specific corrective action and due date for each controllable barrier."},
      {"title": "Staff Presence, Natural Supports, and Follow-Through", "estimated_minutes": 15, "activity_type": "guided_instruction", "content": "Staff behavior can open or close community relationships. Introduce the person directly, speak with rather than for the person, avoid sharing diagnoses, and step back when support is not needed. Help the person learn names, routines, and ways to contribute. Natural support develops through ordinary reciprocity; it is not unpaid replacement staffing and should never be coerced.\n\nDocument the person's choice, participation, interactions, skill use, supports provided, and response. Avoid notes that merely say community outing completed. Review whether activities are repeated because the person values them or because the provider always schedules them. Track cancellations and patterns of missed access as quality concerns.\n\nGuided practice: write a support plan for attending a recurring community activity three times. Describe the staff role on visit one, the support to fade on later visits, the relationship or role the person hopes to develop, and the evidence that will show whether the activity is meaningful."}
    ],
    "scenarios": [
      {"title": "Applied Scenario: The Group Van", "estimated_minutes": 8, "activity_type": "applied_scenario", "content": "Four housemates are scheduled for the same weekly mall trip. Luis repeatedly says he wants to attend a neighborhood photography club instead. Analyze whether the schedule reflects individual choice. Identify discovery questions, transportation and staffing options, accessibility needs, the staff role at the club, and how to document Luis's response. A lack of an existing provider trip is a barrier to solve, not proof that the choice is unavailable."},
      {"title": "Applied Scenario: Private Contact", "estimated_minutes": 8, "activity_type": "applied_scenario", "content": "Ava wants private video calls with a new friend. Staff are worried about online exploitation and propose listening to every call. Apply rights and positive-risk principles: assess Ava's understanding, teach privacy and safety tools, identify warning signs and reporting routes, configure technology with consent, and use the least intrusive monitoring supported by the current plan. Explain when concern becomes a reportable safety issue."}
    ],
    "source_minutes": 4,
    "source_content": "Primary authority: 55 Pa. Code Section 6400.52(c)(1); Section 6400.32 rights to choice, schedule, privacy, access, relationships, and community life; and the DHS Chapter 6400 Regulatory Compliance Guide. Official text: https://www.pacodeandbulletin.gov/secure/pacode/data/055/chapter6400/s6400.52.html and https://www.pacodeandbulletin.gov/secure/pacode/data/055/chapter6400/s6400.32.html. Apply the person's current Individual Plan and the home's approved transportation and safety procedures.",
    "quiz_minutes": 8,
    "questions": [
      {"text": "Which example best demonstrates community integration?", "explanation": "Integration includes chosen, ordinary participation and opportunities for belonging, not presence alone.", "answers": [{"text": "Watching a group activity from the van", "correct": false}, {"text": "Becoming a regular member of a chosen neighborhood club", "correct": true}, {"text": "Taking every resident to the same store", "correct": false}, {"text": "Keeping activities inside the home", "correct": false}]},
      {"text": "What should drive selection of a community activity?", "explanation": "Activities should begin with the person's interests, preferences, goals, and support needs.", "answers": [{"text": "The provider's recurring calendar", "correct": false}, {"text": "The easiest transportation route", "correct": false}, {"text": "The person's informed interests and choices", "correct": true}, {"text": "What other housemates selected", "correct": false}]},
      {"text": "Discovery is useful because it:", "explanation": "Accessible previews and low-pressure trials let a person make informed choices about unfamiliar options.", "answers": [{"text": "Replaces the need for consent", "correct": false}, {"text": "Introduces options the person may not yet know", "correct": true}, {"text": "Requires the person to participate", "correct": false}, {"text": "Lets staff select the final activity", "correct": false}]},
      {"text": "Which staff action best supports a relationship?", "explanation": "Staff remove practical barriers while protecting the person's privacy and control over the relationship.", "answers": [{"text": "Listen to every private call", "correct": false}, {"text": "Choose which friends are acceptable", "correct": false}, {"text": "Help arrange requested transportation and private communication", "correct": true}, {"text": "Share the person's diagnosis with the friend", "correct": false}]},
      {"text": "When a community goal repeatedly fails because no ride is scheduled, staff should:", "explanation": "Transportation is an access barrier that should be analyzed, assigned, and corrected rather than treated as the person's failure.", "answers": [{"text": "Remove the goal because transportation barriers make it unrealistic", "correct": false}, {"text": "Document refusal", "correct": false}, {"text": "Analyze transportation options and assign corrective action", "correct": true}, {"text": "Wait until next year", "correct": false}]},
      {"text":"Which description best defines a natural support?","explanation": "Natural supports arise through ordinary reciprocal relationships and do not substitute for required paid support.", "answers": [{"text": "Anyone who can replace scheduled staff", "correct": false}, {"text": "A reciprocal community relationship the person chooses", "correct": true}, {"text": "A person required to provide free transportation", "correct": false}, {"text": "A staff member's private friendship with the person", "correct": false}]},
      {"text": "A strong community-participation note records:", "explanation": "Useful documentation describes choice, participation, interactions, supports, skill use, and the person's response.", "answers": [{"text": "Community outing completed", "correct": false}, {"text": "Staff drove for two hours", "correct": false}, {"text": "The person's choice, role, support used, interactions, and response", "correct": true}, {"text": "Only the location and date", "correct": false}]},
      {"text": "When staff are concerned about risk in a chosen relationship, the preferred response is to:", "explanation": "Education and proportionate safeguards preserve relationships better than blanket isolation, unless a lawful plan restriction applies.", "answers": [{"text": "Prohibit all contact", "correct": false}, {"text": "Use education and the least intrusive assessed safeguard", "correct": true}, {"text": "Secretly monitor every interaction", "correct": false}, {"text": "Tell the other person private clinical details", "correct": false}]}
    ]
  },
  {
    "catalog_code": "PA-GH-6400-ABUSE-PREVENT-DETECT",
    "title": "Preventing and Detecting Abuse, Neglect, and Exploitation",
    "description": "A comprehensive Chapter 6400 annual-training course on prevention, recognition, immediate protection, trauma-informed response, and professional boundaries. It does not represent Act 31, professional-license CE, or another separately approved credential.",
    "duration_minutes": 120,
    "credit_hours": 2.00,
    "topic_code": "6400.52.C2.ABUSE_PREVENT_DETECT",
    "direct_mode": "verified_only",
    "other_mode": "verified_only",
    "citation_note": "55 Pa. Code Section 6400.52(c)(2): annual training must encompass prevention, detection, and reporting of abuse, suspected abuse, and alleged abuse under the named protective-services laws and regulations.",
    "objectives_minutes": 5,
    "objectives": ["Recognize physical, sexual, emotional, verbal, financial, and digital abuse, neglect, exploitation, abandonment, and rights violations.", "Identify grooming, coercion, retaliation, unexplained change, and environmental warning signs.", "Use immediate protective and trauma-informed responses without investigating or contaminating evidence.", "Apply professional boundaries and prevention practices that reduce opportunity for maltreatment."],
    "lessons": [
      {"title": "What Abuse, Neglect, and Exploitation Can Look Like", "estimated_minutes": 18, "activity_type": "guided_instruction", "content": "Maltreatment may be an act, omission, pattern, threat, or misuse of power. Physical abuse can include hitting, rough handling, inappropriate restraint, painful positioning, or withholding needed assistance. Sexual abuse includes nonconsensual contact, exposure, recording, coercion, or activity when a person cannot consent. Emotional or verbal abuse includes humiliation, threats, intimidation, isolation, and degrading treatment. Neglect can involve failure to provide supervision, healthcare, food, hydration, hygiene, protection, or implementation of ordered supports. Exploitation includes theft, coercive purchases, misuse of benefits, identity misuse, unpaid labor, or manipulating a relationship for gain.\n\nDo not wait for a perfect label. Staff responsibilities begin when there is a reasonable concern, disclosure, observation, or unexplained pattern. A person may communicate through behavior, assistive technology, pictures, gestures, or changes in routine rather than a verbal statement.\n\nGuided practice: create a recognition chart with possible physical, behavioral, financial, environmental, and digital indicators. For each, write a neutral observation statement and the immediate safety question you would ask without leading the person."},
      {"title": "Risk Factors, Grooming, and Power", "estimated_minutes": 18, "activity_type": "guided_instruction", "content": "Abuse grows where power is unchecked, privacy is absent, people are not believed, staffing is unstable, or rules prioritize silence and convenience. Grooming can include special gifts, secrets, isolation, testing boundaries, creating dependency, excessive private contact, or convincing others that the person is unreliable. Financial grooming may start with small loans or shared purchases. Digital grooming may involve private messages, threats, images, or requests for account access.\n\nRisk factors never make the person responsible for abuse. Communication disability, need for intimate support, social isolation, or previous trauma can increase vulnerability while also making disclosure harder. Prevention gives people accessible education about rights, consent, bodies, money, relationships, complaint routes, and how to reach someone outside the immediate staff team.\n\nGuided practice: review your work environment for blind spots, isolated tasks, undocumented one-to-one access, shared passwords, weak cash controls, and retaliation risks. Identify controls that increase transparency without eliminating the person's privacy."},
      {"title": "Respond to a Disclosure or Observation", "estimated_minutes": 18, "activity_type": "guided_instruction", "content": "When someone discloses harm, stay calm, listen, believe the concern, thank the person for telling you, and explain that you must seek help. Ask only the minimal open questions needed to understand immediate danger, such as what happened and whether the person is safe now. Do not interrogate, promise secrecy, confront the alleged actor, pressure the person to repeat details, or insert your interpretation. Preserve spontaneous words and communication as accurately as possible.\n\nAddress urgent medical and safety needs first. Follow emergency and supervisory procedures, separate involved people when required for protection, preserve potential evidence, and make external reports within applicable timelines. Internal notification never replaces a report required by law. Protect the person and reporter from retaliation.\n\nGuided practice: rehearse a five-sentence response to a disclosure: acknowledgment, safety check, minimal clarification, explanation of reporting duty, and reassurance about next steps. Then write an objective contemporaneous note that separates exact words, observations, and actions."},
      {"title": "Neglect, Institutional Practices, and Retaliation", "estimated_minutes": 18, "activity_type": "guided_instruction", "content": "Neglect is not limited to dramatic abandonment. Repeatedly skipping range-of-motion support, leaving a person wet, failing to follow safe-eating procedures, missing medication, sleeping through required supervision, ignoring medical changes, or refusing community access may cause serious harm. Systemic practices can normalize neglect when staffing, schedules, or informal rules routinely override assessed needs.\n\nRetaliation can be explicit or subtle: threatening discharge, withdrawing attention, delaying assistance, labeling the person difficult, restricting activities, changing preferred staff, or exposing a reporter's identity. A complaint or report must never reduce respectful support. Supervisors should monitor for changes after a disclosure.\n\nGuided practice: distinguish an isolated mistake, a pattern of neglect, and an institutional practice using three examples. In every case, identify the immediate protective action, required reporting consultation, documentation, and corrective learning needed."},
      {"title": "Professional Boundaries and Prevention Culture", "estimated_minutes": 15, "activity_type": "guided_instruction", "content": "Professional relationships are warm, respectful, and reliable without becoming exploitative or secret. Staff do not borrow or lend money, accept significant gifts, share passwords, use a person's property, conduct personal business through the person, create secret communications, or seek emotional, sexual, or financial benefit. Follow policy for gifts, social media, transportation, photographs, and contact outside work.\n\nPrevention is a daily culture: people know their rights and reporting options; staff welcome questions; two-person or audit controls protect funds and high-risk tasks; supervisors observe practice; complaints are tracked; incidents are analyzed; and training addresses real patterns. Bystanders intervene safely and report concerns rather than assuming someone else will act.\n\nGuided practice: identify three boundary pressures common in direct support. Write a respectful refusal, a transparent alternative, and the person or system to notify. Then identify how a supervisor can detect and address boundary drift early."}
    ],
    "scenarios": [
      {"title": "Applied Scenario: The Unexplained Bruise", "estimated_minutes": 8, "activity_type": "applied_scenario", "content": "During personal care, you see a large bruise on Sam's upper arm. Sam becomes quiet and pulls away when a particular coworker enters. Practice an objective response: ensure privacy and immediate safety, ask a minimal open question, avoid suggesting an answer, obtain needed medical attention, preserve Sam's words and your observations, and follow both external and internal reporting procedures without confronting the coworker."},
      {"title": "Applied Scenario: Small Loans", "estimated_minutes": 8, "activity_type": "applied_scenario", "content": "A staff member regularly asks Renee for small loans and repays some but not all. The staff member says Renee enjoys helping and the amounts are minor. Identify the power imbalance, financial exploitation and boundary concerns, immediate protection of Renee's funds and account access, records to preserve, reporting consultation, and steps to prevent retaliation. Repayment does not erase the concern."}
    ],
    "source_minutes": 4,
    "source_content": "Primary authority: 55 Pa. Code Sections 6400.16, 6400.17, and 6400.52(c)(2), together with OAPSA, CPSL, APSA, and applicable protective-services regulations. Official Chapter 6400 text: https://www.pacodeandbulletin.gov/secure/pacode/data/055/chapter6400/s6400.52.html. Use current Pennsylvania reporting instructions and the home's emergency/reporting policy. This course is Chapter 6400 annual-training content, not an Act 31 or professional-license CE approval.",
    "quiz_minutes": 8,
    "questions": [
      {"text": "A person communicates possible harm through gestures rather than words. Staff should:", "explanation": "A disclosure may use any communication method and must be taken seriously.", "answers": [{"text": "Wait for a spoken statement", "correct": false}, {"text": "Treat the communication as a concern and follow safety and reporting steps", "correct": true}, {"text": "Ask another resident to interpret", "correct": false}, {"text": "Assume the behavior is unrelated", "correct": false}]},
      {"text": "Which action may be financial exploitation?", "explanation": "Using the professional relationship to borrow money or obtain benefit from a person is a serious boundary and exploitation concern.", "answers": [{"text": "Helping the person review a receipt", "correct": false}, {"text": "Borrowing money from the person and promising repayment", "correct": true}, {"text": "Following the approved funds procedure", "correct": false}, {"text": "Supporting the person's chosen purchase", "correct": false}]},
      {"text": "What is the best initial response to a disclosure?", "explanation": "Staff should remain calm, listen, address immediate safety, and avoid investigative questioning.", "answers": [{"text": "Demand a complete timeline", "correct": false}, {"text": "Confront the alleged actor", "correct": false}, {"text": "Listen calmly, check immediate safety, and ask minimal open questions", "correct": true}, {"text": "Promise the information will remain secret", "correct": false}]},
      {"text": "Internal supervisor notification:", "explanation": "An internal notification process never replaces an external report required by protective-services law.", "answers": [{"text": "Always replaces external reporting", "correct": false}, {"text": "Is enough when the supervisor disagrees", "correct": false}, {"text": "Does not replace a legally required external report", "correct": true}, {"text": "May be delayed until the next shift", "correct": false}]},
      {"text": "Which is a possible form of retaliation?", "explanation": "Withdrawing preferred support or opportunities because someone reported a concern can be retaliation.", "answers": [{"text": "Maintaining ordinary respectful support", "correct": false}, {"text": "Removing activities because the person made a report", "correct": true}, {"text": "Providing requested advocacy", "correct": false}, {"text": "Preserving the reporter's privacy", "correct": false}]},
      {"text": "Which practice best prevents abuse?", "explanation": "Accessible rights education, transparent controls, observation, and responsive complaint systems reduce opportunity and silence.", "answers": [{"text": "Discourage complaints that cannot be proved", "correct": false}, {"text": "Rely only on criminal background checks", "correct": false}, {"text": "Teach accessible reporting options and use transparent safeguards", "correct": true}, {"text": "Eliminate all privacy", "correct": false}]},
      {"text": "A staff member notices a possible pattern of missed safe-eating support. The correct response is to:", "explanation": "Repeated failure to implement an assessed safety procedure may constitute neglect and requires protection, reporting consultation, and correction.", "answers": [{"text": "Wait for an injury", "correct": false}, {"text": "Address immediate safety and follow reporting and corrective procedures", "correct": true}, {"text": "Mention it informally only", "correct": false}, {"text": "Remove the procedure from the plan", "correct": false}]},
      {"text": "Why should staff avoid leading questions after a disclosure?", "explanation": "Leading questions can alter the person's account and interfere with a proper investigation; staff obtain only minimal safety information.", "answers": [{"text": "They take too much time", "correct": false}, {"text": "They can contaminate the account and evidence", "correct": true}, {"text": "Only supervisors may speak to the person", "correct": false}, {"text": "The person must write everything instead", "correct": false}]}
    ]
  },
  {
    "catalog_code": "PA-GH-6400-PROTECTIVE-REPORTING",
    "title": "Reporting Under APSA, OAPSA, and CPSL",
    "description": "A comprehensive Chapter 6400 course on selecting the correct Pennsylvania protective-services pathway, making prompt reports, preserving facts, and coordinating immediate protection. It does not confer Act 31 or other approved continuing-education credit.",
    "duration_minutes": 120,
    "credit_hours": 2.00,
    "topic_code": "6400.52.C2.PROTECTIVE_REPORTING",
    "direct_mode": "verified_only",
    "other_mode": "verified_only",
    "citation_note": "55 Pa. Code Section 6400.52(c)(2) names OAPSA, CPSL, APSA, and applicable protective-services regulations as required annual-training subject matter.",
    "objectives_minutes": 5,
    "objectives": ["Distinguish the populations, reporter-status rules, channels, and timing under APSA, OAPSA, and CPSL without treating the laws as interchangeable.", "Use immediate oral or electronic reporting and required 48-hour written follow-up when the applicable law requires it.", "Recognize serious-abuse categories that trigger additional Department or law-enforcement reporting while continuing Chapter 6400 incident duties.", "Use current Commonwealth instructions and retain separately approved Act 31 or professional credentials when a role requires them."],
    "lessons": [
      {"title": "APSA: Adults Ages 18 Through 59", "estimated_minutes": 18, "activity_type": "guided_instruction", "content": "APSA protects adults ages 18 through 59 with a physical or mental impairment that substantially limits one or more major life activities. A facility administrator or employee who has reasonable cause to suspect abuse, neglect, exploitation, or abandonment of a recipient follows the mandatory-reporting route: assure immediate safety, make the oral report immediately to the statewide Protective Services Hotline at 1-800-490-8505, and send the authorized written report to the current DHS-designated APS recipient within 48 hours. A supervisor may assist but does not become a permission gate.\n\nFor suspected sexual abuse, serious injury, serious bodily injury, or suspicious death, current DHS APS guidance adds immediate oral reports to law enforcement and the DHS APS Division, plus a written report to law enforcement within 48 hours. Contacts and submission methods can change, so the home must verify the current DHS APS guidance and form at the time of training. Guided practice: complete an APS timing card that separately lists the general report, serious-category additions, Chapter 6400 incident work, and emergency response."},
      {"title": "OAPSA: Recipients Age 60 or Older", "estimated_minutes": 18, "activity_type": "guided_instruction", "content": "OAPSA applies to older adults age 60 or older. Pennsylvania Department of Aging guidance states that a facility employee or administrator with reasonable cause to suspect abuse of a recipient must immediately make an oral report to the local Area Agency on Aging and make a written report to that agency within 48 hours; the statewide helpline at 1-800-490-8505 can route a report. An employee immediately notifies the administrator or designee after making the report, but internal notice cannot replace or delay the external report. Department of Aging guidance also directs facility reports to applicable licensing agencies.\n\nSuspected sexual abuse, serious physical injury, serious bodily injury, or suspicious death triggers additional immediate reporting to the Department of Aging and local law enforcement, with written law-enforcement follow-up within 48 hours. Guided practice: compare the general OAPSA route with the serious-abuse route and identify the local AAA, licensing entity, after-hours method, and current written form without copying APSA contacts into the OAPSA column."},
      {"title": "CPSL: Children and Mandated-Reporter Status", "estimated_minutes": 18, "activity_type": "guided_instruction", "content": "CPSL reporter status depends on the person's role and the statutory circumstances; do not assume that every learner has the same duty solely because this Chapter 6400 course mentions CPSL. A mandated reporter with reasonable cause to suspect child abuse makes the report immediately through the Child Welfare Information Solution portal or ChildLine at 1-800-932-0313. A telephone report requires the CY-47 written follow-up to the assigned county agency or OCYF regional office within 48 hours; DHS confirmation of an electronic report removes that separate CY-47 step.\n\nThe reporter does not need proof or a direct disclosure from the child. Protect immediate safety and call 911 when necessary, then report without waiting for a supervisor or an internal interview. Guided practice: decide whether four fictional roles are mandated or permissive reporters, choose the correct channel, and state the follow-up required after telephone versus electronic reporting."},
      {"title": "Parallel Duties, Facts, and Protection", "estimated_minutes": 18, "activity_type": "guided_instruction", "content": "APSA, OAPSA, CPSL, emergency response, law enforcement, licensing notification, and the Chapter 6400 incident process serve different purposes. Completing one record does not automatically satisfy another duty. Protect the person, obtain urgent care, preserve evidence, prevent retaliation, and maintain necessary supports while required reports proceed in parallel. Do not conduct repeated interviews, reconcile accounts, search private devices, or wait for legal certainty.\n\nGive the receiving agency concise facts: identifying information, present location and safety, observed injuries or hazards, exact words, alleged actor if known, witnesses, and actions taken. Label secondhand information and unknown facts. Retain confirmation numbers and written-submission evidence in the authorized record. Guided practice: map one event across emergency, protective-services, serious-category, licensing, Chapter 6400, and ongoing-support lanes and mark every independent deadline."},
      {"title": "Current Guidance, Confidentiality, and Credential Boundary", "estimated_minutes": 15, "activity_type": "guided_instruction", "content": "The home must compare its reporting card with current DHS APS, Department of Aging, and ChildLine guidance because phone options, portals, forms, and submission addresses can change. Share allegations only with authorized people, preserve the reporter's and person's confidentiality, and report retaliation. Do not place sensitive details in group messages or an unapproved email channel.\n\nThis course covers the Chapter 6400 annual subject in Section 6400.52(c)(2). It does not award Act 31 credit and does not replace a separately approved child-abuse course, professional continuing education, or the Commonwealth's own mandatory-reporting training when a role or credential requires it. Guided practice: verify the current Commonwealth pages, record the review date and owner, and identify which learners require external certificates in addition to this Chapter 6400 completion."}
    ],
    "scenarios": [
      {"title": "Applied Scenario: APSA and Serious-Abuse Additions", "estimated_minutes": 8, "activity_type": "applied_scenario", "content": "A 59-year-old recipient with a qualifying disability reports sexual abuse and a threat from the alleged actor. Build a timed response: immediate safety and 911 when needed; immediate APS hotline report; immediate law-enforcement and DHS APS Division reports because this is a serious category; the APS written report and written law-enforcement report within 48 hours; parallel Chapter 6400 action; factual documentation; and protection from retaliation. Identify which current DHS page or guidance must be checked before sending either written report."},
      {"title": "Applied Scenario: OAPSA or CPSL Is Not APSA", "estimated_minutes": 8, "activity_type": "applied_scenario", "content": "Compare two disclosures. A 62-year-old recipient reports suspected financial exploitation, requiring the current OAPSA route through the local AAA, written follow-up within 48 hours, licensing notification, and any serious-category additions. A child reports inappropriate contact, requiring an immediate mandated report through CWIS or ChildLine and, after a telephone report, CY-47 follow-up within 48 hours. Explain why neither report waits for management interviews and why the two age-based pathways, forms, and agencies must not be interchanged."}
    ],
    "source_minutes": 4,
    "source_content": "Primary authority: 55 Pa. Code Sections 6400.16-18 and 6400.52(c)(2), https://www.pacodeandbulletin.gov/secure/pacode/data/055/chapter6400/s6400.52.html. DHS APS overview and current documents: https://www.pa.gov/agencies/dhs/report-abuse/adult-protective-services. DHS Mandatory Reporter Informational Guidance (updated February 2022): https://www.pa.gov/content/dam/copapwp-pagov/en/dhs/documents/about/fraud-and-abuse/documents/APS%20Informational%20Guidance%20Mandatory%20Reporting-February%202022%20update.pdf. Pennsylvania Department of Aging mandatory-reporting guidance: https://www.pa.gov/agencies/aging/aaa-monitoring and https://www.pa.gov/content/dam/copapwp-pagov/en/aging/documents/resources-for-aging-professionals/policy-and-procedure-manual/chapter-vii_-protective-services-%287-2022%29/appendix%20e.2.%20general%20reporting%20provisions%20-%20voluntary%20vs%20mandatory.pdf. DHS CPSL mandated-reporter service: https://www.pa.gov/services/dhs/report-child-abuse-or-neglect-as-a-mandated-reporter and DHS reporting FAQ: https://www.pa.gov/content/dam/copapwp-pagov/en/dhs/documents/keepkidssafe/clearances/documents/kks-reporting-suspected-child-abuse-faq_2024-08-27.pdf. Verify current contacts, forms, and instructions at training and reporting time. This course does not award Act 31 or professional-license continuing education.",
    "quiz_minutes": 8,
    "questions": [
      {"text": "Which description matches the APSA population addressed in this course?", "explanation": "DHS describes APSA as protecting adults ages 18 through 59 whose physical or mental impairment substantially limits one or more major life activities.", "answers": [{"text": "Every person who is at least 60 years old", "correct": false}, {"text": "Adults ages 18 through 59 with the qualifying impairment", "correct": true}, {"text": "Only children who receive residential services", "correct": false}, {"text": "Every adult regardless of age, impairment, or setting", "correct": false}]},
      {"text": "What is the general APSA mandatory-reporting sequence for a facility employee or administrator?", "explanation": "Current DHS APS guidance requires an immediate oral hotline report and an authorized written report to the designated APS recipient within 48 hours.", "answers": [{"text": "Wait for an internal investigation and report only if abuse is proven", "correct": false}, {"text": "Submit only a Chapter 6400 incident record at the end of the month", "correct": false}, {"text": "Immediately call the APS hotline and send the written APS report within 48 hours", "correct": true}, {"text": "Notify only the alleged actor and preserve no confirmation of the report", "correct": false}]},
      {"text": "Which APSA allegation triggers additional immediate reports to law enforcement and the DHS APS Division?", "explanation": "DHS APS guidance identifies sexual abuse, serious injury, serious bodily injury, and suspicious death for additional immediate reporting and written law-enforcement follow-up within 48 hours.", "answers": [{"text": "A routine preference disagreement with no allegation of abuse", "correct": false}, {"text": "A late recreational activity with no injury or safety concern", "correct": false}, {"text": "A scheduling error that does not involve abuse, neglect, or harm", "correct": false}, {"text": "Suspected sexual abuse, serious injury, serious bodily injury, or suspicious death", "correct": true}]},
      {"text": "What does OAPSA generally require from a facility employee who suspects abuse of a recipient age 60 or older?", "explanation": "Department of Aging guidance requires an immediate oral report to the local AAA and a written report within 48 hours, with applicable licensing and serious-category reporting handled separately.", "answers": [{"text": "Immediately report to the local AAA and follow with the written report within 48 hours", "correct": true}, {"text": "Use only the APS written-report destination for adults under age 60", "correct": false}, {"text": "Wait until the next annual training session before reporting the concern", "correct": false}, {"text": "Ask the training vendor to determine whether the allegation is substantiated", "correct": false}]},
      {"text": "How must a CPSL mandated reporter make the initial report of suspected child abuse?", "explanation": "DHS directs mandated reporters to report immediately through the Child Welfare Information Solution portal or by calling ChildLine at 1-800-932-0313.", "answers": [{"text": "Send an unapproved email to the learner's training administrator", "correct": false}, {"text": "Report immediately through CWIS or ChildLine", "correct": true}, {"text": "Wait for a signed confession from the alleged perpetrator", "correct": false}, {"text": "File only an OAPSA report with the Area Agency on Aging", "correct": false}]},
      {"text": "What follow-up applies after a CPSL mandated reporter makes the initial report by telephone?", "explanation": "DHS guidance requires the CY-47 written report within 48 hours after an oral report; an electronically confirmed CWIS report does not require that separate CY-47 follow-up.", "answers": [{"text": "No written follow-up is ever allowed after a telephone report", "correct": false}, {"text": "A new internal interview must be completed before any form is sent", "correct": false}, {"text": "A CY-47 must be sent to the assigned agency within 48 hours", "correct": true}, {"text": "The reporter must instead submit an APS mandatory-reporting form", "correct": false}]},
      {"text": "How do protective-services reports relate to Chapter 6400 incident duties?", "explanation": "The external protective-services route and Chapter 6400 incident process may proceed in parallel because one submission does not automatically satisfy the other duty.", "answers": [{"text": "The first completed record automatically replaces every other reporting duty", "correct": false}, {"text": "Only the home's internal incident record is needed in every situation", "correct": false}, {"text": "The reporter may select whichever single process is most convenient", "correct": false}, {"text": "Each applicable process must be completed without delaying the others", "correct": true}]},
      {"text": "What credential claim does this Chapter 6400 course make?", "explanation": "The course covers Section 6400.52(c)(2) content but does not award Act 31 credit or replace separately approved professional or role-specific training.", "answers": [{"text": "It automatically renews every Pennsylvania professional license", "correct": false}, {"text": "It awards Act 31 credit to every learner who opens the course", "correct": false}, {"text": "It replaces all Commonwealth mandatory-reporter courses and forms", "correct": false}, {"text": "It provides Chapter 6400 content only; external credentials remain separate", "correct": true}]}
    ]
  },
  {
    "catalog_code":"PA-GH-6400-RIGHTS-FOUNDATIONS","title":"Chapter 6400 Individual Rights","description":"Comprehensive annual training on dignity, privacy, choice, access, property, communication, food, healthcare decisions, and freedom from abuse and unnecessary restriction.","duration_minutes":120,"credit_hours":2.00,"topic_code":"6400.52.C3.RIGHTS_FOUNDATIONS","direct_mode":"verified_only","other_mode":"verified_only","citation_note":"55 Pa. Code Sections 6400.31-34 and 6400.52(c)(3).","objectives_minutes":5,
    "objectives":["Identify the rights protected by Chapter 6400.","Recognize routine practices that can become unauthorized restrictions.","Support privacy, access, choice, communication, possessions, food, relationships, and healthcare decisions.","Use the Individual Plan process when a significant risk may require a rights modification."],
    "lessons":[
      {"title":"Rights Belong to the Individual","estimated_minutes":18,"activity_type":"instruction","content":"People do not lose civil or legal rights because they receive residential services. Staff do not grant rights and cannot remove them for convenience, punishment, staffing preference, or because a person needs support. Rights must be explained through the person's communication method and made usable in daily life. Review dignity, nondiscrimination, choice, ordinary risk, refusal, control of schedule, privacy, possessions, communication, relationships, food access, healthcare decisions, and access to the home and bedroom. Guided work: choose six rights and name one observable support, one warning sign of interference, and one accessible complaint option for each."},
      {"title":"Dignity and Respect During Support","estimated_minutes":18,"activity_type":"instruction","content":"Use the person's chosen name and age-respectful language. Speak directly to the person, explain before touching or assisting, seek consent, cover the body during personal care, and protect private information. Humiliation, threats, infantilizing language, unnecessary delay in toileting, talking over the person, or exposing private information can violate rights without leaving a physical injury. Guided work: rewrite five controlling staff phrases as clear, respectful requests that explain the support need and leave room for choice or refusal."},
      {"title":"Privacy, Property, Communication, and Access","estimated_minutes":18,"activity_type":"instruction","content":"Privacy covers the person, bedroom, possessions, records, calls, messages, visits, and relationships. Knock and wait, enter only with permission or lawful emergency authority, protect keys, and avoid unauthorized searches. Never use a person's money, phone, subscriptions, vehicle, food, or property for staff benefit. Support private calls and visitors while implementing only current assessed safeguards. Guided work: audit medication time, shift report, laundry, visitor arrival, and bedroom checks for privacy risks and identify the least intrusive correction."},
      {"title":"Choice, Refusal, Food, Schedule, and Healthcare","estimated_minutes":18,"activity_type":"instruction","content":"A person may choose activities and schedules, refuse participation, access food, and make healthcare decisions. Explain options and consequences accessibly, confirm understanding, and explore pain, fear, timing, communication, or alternatives. House routines cannot silently replace rights. Blanket food locks, universal bedtimes, mandatory group activities, or withholding preferred items require review. Guided work: analyze a refused medical appointment by separating the person's choice, urgent risk, communication support, practitioner notification, alternatives, and documentation."},
      {"title":"Advocacy, Complaints, and Accountability","estimated_minutes":15,"activity_type":"instruction","content":"Make grievance and outside-contact information accessible. Staff may help communicate without editing the concern. Complaints must not cause threats, delayed assistance, reduced support, lost activities, or exposure of the reporter. Address immediate harm, listen, notify required roles, and document facts. Supervisors should analyze repeated restrictions or complaints as system problems. Guided work: design a complaint path for a person who communicates with pictures, including private access, confirmation, nonretaliation, and follow-up."}
    ],
    "scenarios":[{"title":"Scenario: Locked Refrigerator","estimated_minutes":8,"activity_type":"scenario","content":"Staff lock the refrigerator because one person has a dietary risk, preventing everyone from accessing food. Identify affected rights, immediate alternatives, individualized safeguards, the plan-review path, and documentation. One person's assessed need does not justify a blanket restriction."},{"title":"Scenario: Bedroom Entry","estimated_minutes":8,"activity_type":"scenario","content":"A staff member uses a master key to enter Priya's bedroom for routine laundry while she is away. There is no emergency or permission. Analyze privacy, consent, property, corrective action, documentation, and a respectful housekeeping alternative."}],
    "source_minutes":4,"source_content":"Primary authority: 55 Pa. Code Sections 6400.31-34 and 6400.52(c)(3). Official text: https://www.pacodeandbulletin.gov/secure/pacode/data/055/chapter6400/s6400.32.html and https://www.pacodeandbulletin.gov/secure/pacode/data/055/chapter6400/s6400.52.html. Apply the current Individual Plan and grievance procedures.","quiz_minutes":8,
    "questions":[
      {"text":"Who grants Chapter 6400 rights?","explanation":"Chapter 6400 rights belong to the person; staff must make those rights usable and may not withdraw them for convenience or control.","answers":[{"text":"The shift supervisor acting without legal or plan authority","correct":false},{"text":"The service provider acting through an informal administrative decision","correct":false},{"text":"No staff member; they belong to the individual","correct":true},{"text":"The person's roommate or another resident in the home","correct":false}]},
      {"text":"Which action protects privacy during personal care?","explanation":"Explain, seek consent, close the space, and keep the person covered.","answers":[{"text":"Leave the door open","correct":false},{"text":"Explain, seek consent, and shield the body","correct":true},{"text":"Discuss care in the hall","correct":false},{"text":"Invite observers","correct":false}]},
      {"text":"A person refuses an activity. Staff should first:","explanation":"Refusal is communication and a protected choice. It protects the person's Chapter 6400 right and prevents an informal convenience-based restriction.","answers":[{"text":"Remove a privilege","correct":false},{"text":"Clarify the choice and support needs","correct":true},{"text":"Mark noncompliance","correct":false},{"text":"Force attendance","correct":false}]},
      {"text":"Which is an improper blanket restriction?","explanation":"Restrictions must be individualized and plan-based. It protects the person's Chapter 6400 right and prevents an informal convenience-based restriction.","answers":[{"text":"An adaptive plate","correct":false},{"text":"Locking food from everyone for one person's risk","correct":true},{"text":"Offering meal choices","correct":false},{"text":"Following a diet order","correct":false}]},
      {"text":"When may staff enter a locked bedroom without permission?","explanation":"Routine convenience is insufficient; a life-safety emergency permits access.","answers":[{"text":"For routine laundry when the person has not given permission","correct":false},{"text":"For a routine inspection when there is no emergency or permission","correct":false},{"text":"In a life-safety emergency","correct":true},{"text":"Whenever the person leaves","correct":false}]},
      {"text":"A complaint may result in:","explanation":"A person may complain without losing assistance, activities, or respectful treatment; any adverse change tied to the complaint is prohibited retaliation.","answers":[{"text":"Suspend preferred activities until the complaint is withdrawn","correct":false},{"text":"Reduced staff assistance because the person filed a complaint","correct":false},{"text":"A respectful response without retaliation","correct":true},{"text":"Automatic discharge","correct":false}]},
      {"text":"Rights information is accessible when:","explanation":"It uses the person's communication method and supports action.","answers":[{"text":"Filed in an office","correct":false},{"text":"Explained through the person's communication method","correct":true},{"text":"Read only by staff","correct":false},{"text":"Discussed once verbally, without checking comprehension or access","correct":false}]},
      {"text":"An ongoing rights limitation requires:","explanation":"Use the lawful Individual Plan process, not an informal shift rule.","answers":[{"text":"A verbal shift rule","correct":false},{"text":"The proper Individual Plan process","correct":true},{"text":"A staff vote that overrides the person's rights without plan review","correct":false},{"text":"A handwritten sign","correct":false}]}
    ]
  },
  {
    "catalog_code":"PA-GH-6400-RIGHTS-DAILY-PRACTICE","title":"Rights in Daily Practice: Privacy, Risk, Funds, and Grievances","description":"Applied Chapter 6400 annual training on shift decisions, funds safeguards, positive risk, grievance response, and objective rights documentation.","duration_minutes":120,"credit_hours":2.00,"topic_code":"6400.52.C3.RIGHTS_DAILY_PRACTICE","direct_mode":"verified_only","other_mode":"verified_only","citation_note":"55 Pa. Code Sections 6400.22-23, 6400.31-34, and 6400.52(c)(3).","objectives_minutes":5,
    "objectives":["Apply rights during personal care, meals, schedules, visitors, technology, and community support.","Safeguard funds without taking control from the person.","Use positive-risk analysis rather than informal restrictions.","Receive and track grievances without retaliation."],
    "lessons":[
      {"title":"The Rights Pause","estimated_minutes":18,"activity_type":"instruction","content":"Before directing a person, pause: What right is involved? What is the person communicating? Is there immediate assessed danger? What is the least intrusive support? Does the current plan authorize a limitation? Who must be notified? Apply the pause to personal care, meals, transportation, visitors, technology, and bedtime. Guided work: rewrite five routine shift directives as respectful support interactions that preserve choice and identify genuine nonnegotiable safety steps."},
      {"title":"Funds, Property, Receipts, and Conflicts","estimated_minutes":18,"activity_type":"instruction","content":"The person's money and property remain theirs. Keep funds separate, document transactions promptly, retain receipts, reconcile balances, and provide understandable access. Never borrow, pool, substitute, pre-sign, use loyalty rewards personally, or hide a discrepancy by replacing money. Support informed spending without imposing staff taste. Guided work: reconcile a fictional ledger, receipt, cash balance, and change; identify the discrepancy, evidence, notification, and safeguarding response."},
      {"title":"Positive Risk and Rights Modification","estimated_minutes":18,"activity_type":"instruction","content":"Define the actual risk, invite the person's view, provide decision support, and test less intrusive education, equipment, environmental changes, or graduated practice. Avoid vague labels such as unsafe. An ongoing modification must address a significant risk through the current Individual Plan and be no broader or longer than necessary. Guided work: analyze a proposed technology restriction and document evidence, alternatives, review date, and conditions for restoring access."},
      {"title":"Grievances and Nonretaliation","estimated_minutes":18,"activity_type":"instruction","content":"A grievance may be verbal, written, behavioral, or communicated by a representative. Listen without demanding proof, explain next steps, preserve privacy, route promptly, and support outside advocacy. Retaliation includes threats, ridicule, delayed care, exclusion, or pressure to withdraw. Guided work: create a complaint receipt with requested remedy, safety response, owner, deadline, feedback method, and retaliation check."},
      {"title":"Document Rights Support and Correct Drift","estimated_minutes":15,"activity_type":"instruction","content":"Record the person's choice, accessible information, support offered, observed response, relevant risk, and action. Replace blame labels with facts. When emergency restriction occurs, record necessity, duration, notifications, and follow-up. Supervisors should sample notes, funds, complaints, schedules, and restrictions for patterns. Guided work: rewrite three judgmental notes objectively and choose a quality measure that can reveal recurring rights drift."}
    ],
    "scenarios":[{"title":"Scenario: Missing Receipt","estimated_minutes":8,"activity_type":"scenario","content":"A ledger shows a 20-dollar purchase, no receipt, and five dollars missing. Explain why quiet replacement is inadequate. Identify safeguarding, objective documentation, notification, reconciliation, possible exploitation review, and nonretaliation."},{"title":"Scenario: Standing Emergency Rule","estimated_minutes":8,"activity_type":"scenario","content":"After one unsafe exit, staff lock away everyone's access devices each evening. Identify affected rights, the individual risk, less restrictive measures, current-plan review, restoration of access, and why emergency action cannot become a blanket rule."}],
    "source_minutes":4,"source_content":"Primary authority: 55 Pa. Code Sections 6400.22, 6400.23, 6400.31-34, and 6400.52(c)(3), in the official Chapter 6400 text at https://www.pacodeandbulletin.gov/secure/pacode/data/055/chapter6400/chap6400toc.html.","quiz_minutes":8,
    "questions":[
      {"text":"What should staff do with unexplained missing money?","explanation":"Protect funds, preserve records, reconcile, and report. It keeps the safeguard individualized, transparent, and reviewable instead of relying on an informal shortcut.","answers":[{"text":"Replace it secretly","correct":false},{"text":"Ignore the missing money because no theft has been proven","correct":false},{"text":"Safeguard, document, reconcile, and report","correct":true},{"text":"Charge every resident an equal share of the missing amount","correct":false}]},
      {"text":"Positive-risk support begins with:","explanation":"Define the real risk and the person's goal. It keeps the safeguard individualized, transparent, and reviewable instead of relying on an informal shortcut.","answers":[{"text":"A blanket prohibition imposed before discussing risks and supports","correct":false},{"text":"The actual risk and desired goal","correct":true},{"text":"A blanket house rule imposed without an individualized risk review","correct":false},{"text":"Staff preference","correct":false}]},
      {"text":"Which funds practice is prohibited?","explanation":"Staff may not borrow from people they support. It keeps the safeguard individualized, transparent, and reviewable instead of relying on an informal shortcut.","answers":[{"text":"Keeping receipts","correct":false},{"text":"Reconciling the person's funds with receipts and the current balance","correct":false},{"text":"Borrowing and repaying later","correct":true},{"text":"Explaining choices","correct":false}]},
      {"text":"A grievance may be communicated through:","explanation":"Accessible forms of communication must be recognized. It keeps the safeguard individualized, transparent, and reviewable instead of relying on an informal shortcut.","answers":[{"text":"Only a legal form","correct":false},{"text":"Only an attorney","correct":false},{"text":"Verbal, written, behavioral, or representative communication","correct":true},{"text":"Only an annual meeting","correct":false}]},
      {"text":"Which action is prohibited retaliation after a complaint?","explanation":"Reducing opportunity because of a complaint is retaliation. It keeps the safeguard individualized, transparent, and reviewable instead of relying on an informal shortcut.","answers":[{"text":"Explaining timelines","correct":false},{"text":"Reducing outings after a complaint","correct":true},{"text":"Offering advocacy","correct":false},{"text":"Recording a remedy","correct":false}]},
      {"text":"A rights modification must be:","explanation":"It is individualized, plan-based, and least restrictive. It keeps the safeguard individualized, transparent, and reviewable instead of relying on an informal shortcut.","answers":[{"text":"A permanent verbal rule","correct":false},{"text":"The same for everyone","correct":false},{"text":"Plan-based, individualized, and least restrictive","correct":true},{"text":"Created each shift","correct":false}]},
      {"text":"Which documentation entry is objective and observable?","explanation":"Describe observable communication and action without motive labels.","answers":[{"text":"Maya was manipulative","correct":false},{"text":"Maya said no and accepted a later option","correct":true},{"text":"Maya wanted attention","correct":false},{"text":"Maya was bad and deliberately caused problems for the shift","correct":false}]},
      {"text":"Why analyze rights patterns?","explanation":"Patterns expose system-level restrictions missed in isolated reviews.","answers":[{"text":"To reduce records","correct":false},{"text":"To identify recurring system failures","correct":true},{"text":"To blame one shift","correct":false},{"text":"To avoid individualized planning and impose one rule on everyone","correct":false}]}
    ]
  },
  {
    "catalog_code":"PA-GH-6400-INCIDENT-RESPONSE","title":"Recognizing Incidents and Immediate Protective Action","description":"Comprehensive annual training on incident recognition, emergency triage, immediate protection, notifications, evidence preservation, and continued support.","duration_minutes":120,"credit_hours":2.00,"topic_code":"6400.52.C4.INCIDENT_RESPONSE","direct_mode":"verified_only","other_mode":"verified_only","citation_note":"55 Pa. Code Sections 6400.18-20 and 6400.52(c)(4).","objectives_minutes":5,
    "objectives":["Recognize events requiring emergency, protective-services, or Chapter 6400 action.","Prioritize life safety and protection.","Make timely parallel notifications.","Preserve facts and evidence while supporting the person."],
    "lessons":[
      {"title":"Recognize More Than Obvious Injury","estimated_minutes":18,"activity_type":"instruction","content":"Incidents may include death, hospitalization, injury, abuse, neglect, exploitation, missing person, medication error, rights violation, restraint, law-enforcement involvement, fire, or emergency relocation. Near misses and patterns also require safety review. Staff need not make a final legal classification before acting. Notice unexplained changes, conflicting accounts, hazards, absent supervision, missing funds, and disclosures. Guided work: sort fictional events into emergency, protective services, Chapter 6400, routine documentation, and quality lanes; mark events belonging in several lanes."},
      {"title":"Life Safety and Immediate Protection","estimated_minutes":18,"activity_type":"instruction","content":"Call 911 or obtain urgent care when needed, provide only care within training, follow individual emergency procedures, remove hazards, maintain supervision, account for people, and separate involved parties when required. Preserve evidence unless safety requires movement. Explain actions through the person's communication method and protect privacy. Guided work: list the first five actions for an unexplained serious injury and label the life-safety, communication, evidence, and reporting purpose of each."},
      {"title":"Notifications and Closed-Loop Communication","estimated_minutes":18,"activity_type":"instruction","content":"Events may require emergency services, healthcare, protective services, law enforcement, incident management, licensing, representatives, and leadership. Internal notice never replaces a required external report. State condition, facts, actions, location, and callback; repeat instructions; record time, recipient, and confirmation. Use backup contacts when necessary. Guided work: build a day, evening, weekend, and outage notification tree."},
      {"title":"Preserve Evidence; Do Not Investigate","estimated_minutes":18,"activity_type":"instruction","content":"Protect the scene, records, medications, devices, clothing, exact words, and electronic evidence. Do not clean, discard, alter logs, coordinate stories, or confront an alleged actor. Ask only minimal open questions for safety. Authorized investigators decide credibility and findings. Guided work: identify evidence to protect and actions to avoid for a medication error, missing funds, and possible assault."},
      {"title":"Continue Support and Prevent Secondary Harm","estimated_minutes":15,"activity_type":"instruction","content":"Continue ordinary support, health monitoring, privacy, accessible information, and protection from retaliation. Do not require repeated retelling. Shift handoff shares necessary safety instructions without gossip and names outstanding actions and owners. Supervisors verify medical follow-up, reports, protection, and plan review. Guided work: create a 24-hour follow-up checklist."}
    ],
    "scenarios":[{"title":"Scenario: Changing Symptoms After a Fall","estimated_minutes":8,"activity_type":"scenario","content":"Eli falls, initially says he is fine, then becomes confused and vomits. Apply urgent medical response, individual procedures, supervision, notification, scene facts, and reporting. Explain why the earlier statement does not end monitoring."},{"title":"Scenario: Missing Person","estimated_minutes":8,"activity_type":"scenario","content":"At shift change Nia cannot be located and the sign-out log is blank. Outline plan-based search and emergency action, notification, last-known facts, support for others, documentation, and why fault-finding must wait."}],
    "source_minutes":4,"source_content":"Primary authority: 55 Pa. Code Sections 6400.18-20 and 6400.52(c)(4), available at https://www.pacodeandbulletin.gov/secure/pacode/data/055/chapter6400/chap6400toc.html. Use current ODP incident definitions and the person's emergency plan.","quiz_minutes":8,
    "questions":[
      {"text":"What comes first in life-threatening danger?","explanation":"Protect life and obtain urgent help before administrative work.","answers":[{"text":"Complete the form","correct":false},{"text":"Protect life and obtain emergency help","correct":true},{"text":"Interview witnesses","correct":false},{"text":"Contact the on-call supervisor before activating emergency medical services","correct":false}]},
      {"text":"Must staff know the final classification before acting?","explanation":"Staff protect the person and make required notifications based on the observed concern; authorized reviewers determine the final incident classification.","answers":[{"text":"Always; staff must determine the final legal classification before protecting anyone","correct":false},{"text":"Only on weekends","correct":false},{"text":"No; act on safety and consult definitions","correct":true},{"text":"Only for injuries","correct":false}]},
      {"text":"Which is an appropriate initial question?","explanation":"An open safety-focused question obtains only the information needed for protection and avoids suggesting facts that could contaminate an investigation.","answers":[{"text":"He hit you, right?","correct":false},{"text":"Why did you cause it?","correct":false},{"text":"Can you tell me what happened and if you are safe?","correct":true},{"text":"Are you exaggerating?","correct":false}]},
      {"text":"Closed-loop notification includes:","explanation":"Confirm instructions, recipient, and time. It protects life and evidence while allowing the authorized incident process to determine final findings.","answers":[{"text":"An unclear voicemail","correct":false},{"text":"An unverified group rumor with no identified notification recipient","correct":false},{"text":"Clear facts, confirmed instructions, recipient, and time","correct":true},{"text":"Wait for a later shift before making the required notification","correct":false}]},
      {"text":"Which action preserves evidence?","explanation":"Protecting the original scene and documenting only safety-required changes preserves evidence for the authorized investigator.","answers":[{"text":"Clean immediately","correct":false},{"text":"Rewrite earlier logs so all staff accounts use identical wording","correct":false},{"text":"Protect the scene and document safety changes","correct":true},{"text":"Forward images broadly","correct":false}]},
      {"text":"Does supervisor notice replace external reporting?","explanation":"Required external reports remain required. It protects life and evidence while allowing the authorized incident process to determine final findings.","answers":[{"text":"Always; notifying a supervisor satisfies every required external report","correct":false},{"text":"On weekends, when external agencies are assumed to be unavailable","correct":false},{"text":"No, not when external reporting is required","correct":true},{"text":"After an interview","correct":false}]},
      {"text":"After an incident staff should:","explanation":"Continue support, monitoring, privacy, and nonretaliation. It protects life and evidence while allowing the authorized incident process to determine final findings.","answers":[{"text":"Require repeated retelling","correct":false},{"text":"Continue dignified support and monitoring","correct":true},{"text":"Discuss publicly","correct":false},{"text":"Invent restrictions","correct":false}]},
      {"text":"How should staff respond to a safety-related near miss?","explanation":"Review near misses for prevention and reporting duties. It protects life and evidence while allowing the authorized incident process to determine final findings.","answers":[{"text":"Ignored because no injury occurred and prevention review is unnecessary","correct":false},{"text":"Deleted so the near miss cannot be reviewed for prevention","correct":false},{"text":"Reviewed for prevention and any reporting duty","correct":true},{"text":"Kept secret from authorized reviewers and future prevention efforts","correct":false}]}
    ]
  },
  {
    "catalog_code":"PA-GH-6400-INCIDENT-DOCUMENTATION","title":"Incident Documentation, Investigation, and Prevention","description":"Applied annual training on objective records, certified-investigation boundaries, corrective action, trend analysis, and prevention.","duration_minutes":120,"credit_hours":2.00,"topic_code":"6400.52.C4.INCIDENT_DOCUMENTATION","direct_mode":"verified_only","other_mode":"verified_only","citation_note":"55 Pa. Code Sections 6400.18-20, 6400.50, and 6400.52(c)(4).","objectives_minutes":5,
    "objectives":["Write chronological objective incident records.","Respect certified-investigation boundaries.","Create root-cause corrective actions.","Analyze trends and verify prevention."],
    "lessons":[
      {"title":"Objective and Complete Records","estimated_minutes":18,"activity_type":"instruction","content":"Record date, time, location, people, baseline, changed condition, exact observations, quotes, actions, notifications, instructions, and disposition. Attribute information and write unknown when unknown. Avoid labels such as aggressive, manipulative, or fine without detail. Never backdate, erase, or coordinate accounts. Guided work: rewrite a judgmental note and label every sentence as observation, quote, action, notification, or attributed information."},
      {"title":"Timeline, Handoff, and Integrity","estimated_minutes":18,"activity_type":"instruction","content":"Align original logs, medication records, schedules, medical notes, and contacts without changing them to match. Each author records only what they know; late entries are labeled. Handoff identifies unresolved safety actions and owners. Protect confidentiality and audit trails; do not photograph records or use informal group chat. Guided work: arrange three accounts into a source-attributed timeline and flag contradictions without choosing a winner."},
      {"title":"Certified Investigation Boundaries","estimated_minutes":18,"activity_type":"instruction","content":"Specified serious incidents require a Department-certified investigator. Direct staff protect, report, preserve, and cooperate; they do not make findings, test credibility, or direct witnesses. During interview, distinguish what you saw, heard, did, and learned later; say when you do not remember. Guided work: classify ten questions as immediate-safety clarification or investigator work."},
      {"title":"Root Cause and Corrective Action","estimated_minutes":18,"activity_type":"instruction","content":"Examine plan clarity, staffing, workload, communication, equipment, environment, scheduling, supervision, policy, and prior warnings. Do not substitute blame for cause. Actions must be specific, assigned, dated, measurable, and verified. Training fits a true knowledge gap but cannot repair broken equipment or impossible workflows. Guided work: conduct a five-why analysis and compare a weak reminder with a strong system correction."},
      {"title":"Trend Analysis and Learning","estimated_minutes":15,"activity_type":"instruction","content":"Analyze incidents by type, person, location, time, staff pattern, injury, cause, and action while protecting privacy. Look for recurrence, clusters, overdue work, medication errors, falls, missing-person events, rights concerns, and near misses. Verify that actions occurred and changed outcomes. Guided work: review a fictional quarterly dashboard, identify two patterns, and choose leading and lagging measures."}
    ],
    "scenarios":[{"title":"Scenario: Judgmental Note","estimated_minutes":8,"activity_type":"scenario","content":"A draft says Carlos became aggressive for no reason and attacked staff. Rewrite it with observable movement, words, distance, environment, injury, response, and direct quotes. Identify what belongs to later investigation."},{"title":"Scenario: Repeat Medication Errors","estimated_minutes":8,"activity_type":"scenario","content":"Three late doses on weekends were each closed with retraining. Analyze schedules, packaging, handoff, staffing, MAR design, supervision, and prior verification; propose system actions and outcome measures."}],
    "source_minutes":4,"source_content":"Primary authority: 55 Pa. Code Sections 6400.18-20, 6400.50, and 6400.52(c)(4), at https://www.pacodeandbulletin.gov/secure/pacode/data/055/chapter6400/chap6400toc.html. This course does not certify an investigator.","quiz_minutes":8,
    "questions":[
      {"text":"Which phrase is objective?","explanation":"Describe observable behavior and exact words. It preserves an auditable factual record for certified investigation and corrective-action review.","answers":[{"text":"Carlos was manipulative","correct":false},{"text":"Carlos pushed the chair and said leave me alone","correct":true},{"text":"Carlos attacked for no reason","correct":false},{"text":"Carlos was bad and caused the entire incident on purpose","correct":false}]},
      {"text":"When a fact is unknown, write:","explanation":"Writing unknown and identifying the source of available information preserves record integrity; selecting a likely answer creates false evidence.","answers":[{"text":"The likeliest answer","correct":false},{"text":"Unknown with the source of known information","correct":true},{"text":"Another person's guess","correct":false},{"text":"Nothing anywhere","correct":false}]},
      {"text":"What should a direct worker do during an incident investigation?","explanation":"Protect, report, preserve, and cooperate. It preserves an auditable factual record for certified investigation and corrective-action review.","answers":[{"text":"Determine credibility","correct":false},{"text":"Obtain confessions","correct":false},{"text":"Protect, report, preserve, and cooperate","correct":true},{"text":"Close the investigation findings without certified-review authority","correct":false}]},
      {"text":"A strong corrective action:","explanation":"Address cause, assign ownership and time, and verify. It preserves an auditable factual record for certified investigation and corrective-action review.","answers":[{"text":"Tell staff to be more careful without an owner, deadline, or measure","correct":false},{"text":"Retrains regardless of cause","correct":false},{"text":"Repairs the cause with owner, date, and verification","correct":true},{"text":"Closes the case quickly without identifying cause or prevention","correct":false}]},
      {"text":"Why preserve contradictory accounts?","explanation":"Authorized investigators evaluate original information. It preserves an auditable factual record for certified investigation and corrective-action review.","answers":[{"text":"To embarrass staff","correct":false},{"text":"For authorized evaluation of original evidence","correct":true},{"text":"To vote on truth","correct":false},{"text":"To avoid reporting","correct":false}]},
      {"text":"How should staff create a necessary late documentation entry?","explanation":"Label and complete it under policy, never backdate. It preserves an auditable factual record for certified investigation and corrective-action review.","answers":[{"text":"Backdated so the entry appears to have been recorded earlier","correct":false},{"text":"Written over the original","correct":false},{"text":"Labeled according to policy","correct":true},{"text":"Sent only by text","correct":false}]},
      {"text":"Trend analysis should include:","explanation":"Look for relationships across type, time, location, causes, and outcomes.","answers":[{"text":"Only annual totals, with no analysis by person, location, time, or cause","correct":false},{"text":"Patterns, causes, actions, and outcomes","correct":true},{"text":"Only confirmed abuse incidents, excluding near misses and other patterns","correct":false},{"text":"Only injuries, excluding medication, rights, or missing-person patterns","correct":false}]},
      {"text":"Retraining alone fails when:","explanation":"Training cannot correct a nontraining system defect. It preserves an auditable factual record for certified investigation and corrective-action review.","answers":[{"text":"Knowledge is missing","correct":false},{"text":"The cause is broken equipment or workflow","correct":true},{"text":"Practice is requested","correct":false},{"text":"A new rule exists","correct":false}]}
    ]
  },
  {
    "catalog_code":"PA-GH-6400-HEALTH-SAFETY","title":"Health Observation, Infection Prevention, and Individual Emergencies","description":"Job-skills annual training on recognizing health change, infection prevention, safe support, and individual emergency plans; not clinical licensure or skills certification.","duration_minutes":60,"credit_hours":1.00,"topic_code":"6400.52.JOB_HEALTH_SAFETY","direct_mode":"verified_only","other_mode":"verified_only","citation_note":"55 Pa. Code Section 6400.52(a), job skills and knowledge; Sections 6400.141-151 health and emergency-plan requirements.","objectives_minutes":4,"objectives":["Recognize and escalate changes from baseline.","Use infection-prevention precautions.","Follow person-specific eating, mobility, skin, respiratory, and emergency instructions.","Document observations without diagnosing."],
    "lessons":[
      {"title":"Baseline and Change","estimated_minutes":8,"activity_type":"instruction","content":"Know each person's usual communication, appetite, movement, sleep, skin, breathing, elimination, mood, and alertness. Compare current observation with baseline and the plan; do not diagnose. Sudden confusion, breathing difficulty, severe pain, unresponsiveness, uncontrolled bleeding, or other emergency signs require immediate action. Practice describing a change with time, measurement, direct quote, and action."},
      {"title":"Infection Prevention","estimated_minutes":8,"activity_type":"instruction","content":"Perform hand hygiene at required moments, use personal protective equipment correctly, clean and disinfect according to product and facility instructions, separate clean from contaminated items, and report symptoms or exposure. Never reuse single-use equipment or allow gloves to replace hand hygiene. Review the home's current outbreak and exclusion procedure."},
      {"title":"Eating, Mobility, Skin, and Respiratory Safety","estimated_minutes":8,"activity_type":"instruction","content":"Follow only current individual instructions for food texture, liquid consistency, pacing, positioning, transfer equipment, skin protection, respiratory treatment, and supervision. Do not improvise or copy another person's procedure. Stop and seek qualified direction when instructions are missing, conflicting, or the person's condition changes."},
      {"title":"Individual Emergency Plans","estimated_minutes":8,"activity_type":"instruction","content":"Know where the current emergency plan is, the person's warning signs, first action, rescue medication or equipment boundaries, emergency contacts, and what information travels with the person. Call emergency services when required; contacting a supervisor cannot delay urgent care. Practice locating and explaining one current plan without exposing private information."},
      {"title":"Report and Document","estimated_minutes":8,"activity_type":"instruction","content":"Record observable signs, onset, vital information if trained and ordered, support provided, contacts, instructions, and response. Avoid diagnostic claims and vague phrases such as seemed fine. Handoff unresolved monitoring and follow-up through the authorized channel. Report missing or outdated instructions before the next emergency."}
    ],
    "scenarios":[{"title":"Scenario: Coughing During a Meal","estimated_minutes":4,"activity_type":"scenario","content":"A person coughs repeatedly and becomes flushed while eating. Apply the person's safe-eating and emergency plan, trained response, urgent escalation, observation, notification, and documentation; do not invent a new texture order."},{"title":"Scenario: Sudden Confusion","estimated_minutes":4,"activity_type":"scenario","content":"A normally alert person becomes confused and unsteady. Identify immediate safety, emergency assessment, baseline comparison, contacts, medication-record information, and handoff."}],
    "source_minutes":3,"source_content":"Primary authority: 55 Pa. Code Sections 6400.52, 6400.141-151, and applicable current Individual Plans, at https://www.pacodeandbulletin.gov/secure/pacode/data/055/chapter6400/chap6400toc.html. This course does not authorize a clinical procedure.","quiz_minutes":5,
    "questions":[
      {"text":"Staff should describe health change by:","explanation":"Report observable facts and comparison with baseline, not a diagnosis.","answers":[{"text":"Diagnosing the medical cause without qualified clinical authority","correct":false},{"text":"Guessing the likely cause instead of reporting observable change","correct":false},{"text":"Recording observable change, time, and action","correct":true},{"text":"Wait for a later shift before making the required notification","correct":false}]},
      {"text":"Gloves replace hand hygiene:","explanation":"Hands still require hygiene at applicable moments. It protects the person by using current instructions, observable facts, and timely qualified escalation.","answers":[{"text":"Always; wearing gloves removes the need for hand hygiene","correct":false},{"text":"Only at meals, even though contamination can occur at other times","correct":false},{"text":"Never; gloves do not replace required hand hygiene","correct":true},{"text":"When staff are rushed, even though hand hygiene is still required","correct":false}]},
      {"text":"A safe-eating procedure should come from:","explanation":"Use the person's current authorized instructions. It protects the person by using current instructions, observable facts, and timely qualified escalation.","answers":[{"text":"Another resident's plan","correct":false},{"text":"Staff preference","correct":false},{"text":"The current person-specific plan or order","correct":true},{"text":"An outdated shift note rather than the current authorized procedure","correct":false}]},
      {"text":"Urgent medical help may be delayed for supervisor permission:","explanation":"Immediate emergencies require prompt emergency action. It protects the person by using current instructions, observable facts, and timely qualified escalation.","answers":[{"text":"Always; staff must wait for supervisor permission before urgent medical help","correct":false},{"text":"At night, even when the person has signs of a medical emergency","correct":false},{"text":"No; emergency medical response must not wait for supervisor permission","correct":true},{"text":"For new staff who have not yet received the supervisor's permission","correct":false}]},
      {"text":"Which is a useful handoff?","explanation":"State unresolved monitoring, instructions, and owners. It protects the person by using current instructions, observable facts, and timely qualified escalation.","answers":[{"text":"Everything is fine","correct":false},{"text":"Monitor temperature at 8 p.m. and call the nurse at the listed threshold","correct":true},{"text":"Watch closely, with no stated observation, time, action, or escalation","correct":false},{"text":"Maybe sick, with no observation, time, baseline, or action","correct":false}]},
      {"text":"When instructions conflict, staff should:","explanation":"Pause nonurgent action and obtain qualified clarification. It protects the person by using current instructions, observable facts, and timely qualified escalation.","answers":[{"text":"Choose whichever instruction seems easiest and ignore the conflict","correct":false},{"text":"Copy another plan","correct":false},{"text":"Seek qualified clarification and protect safety","correct":true},{"text":"Ignore both instructions and continue without resolving the conflict","correct":false}]},
      {"text":"Single-use equipment may be reused:","explanation":"Single-use items are discarded according to procedure. It protects the person by using current instructions, observable facts, and timely qualified escalation.","answers":[{"text":"If clean-looking","correct":false},{"text":"For one house, even though the equipment is labeled single use","correct":false},{"text":"No; equipment labeled single use must be discarded after one use","correct":true},{"text":"After rinsing, even though the item is designated for single use","correct":false}]},
      {"text":"This course authorizes clinical procedures:","explanation":"It provides awareness, not licensure or procedure competency.","answers":[{"text":"All clinical procedures, regardless of staff qualification or authorization","correct":false},{"text":"Medication injection","correct":false},{"text":"No; separate qualification is required","correct":true},{"text":"Any emergency treatment","correct":false}]}
    ]
  },
  {
    "catalog_code":"PA-GH-6400-DOCUMENTATION-FUNDS","title":"Records, Confidentiality, and Safeguarding Individual Funds","description":"Job-skills annual training on accurate records, minimum-necessary confidentiality, individual funds, property, receipts, and audit-ready corrections.","duration_minutes":60,"credit_hours":1.00,"topic_code":"6400.52.JOB_DOCUMENTATION_FUNDS","direct_mode":"verified_only","other_mode":"verified_only","citation_note":"55 Pa. Code Sections 6400.22, 6400.50, 6400.213, and 6400.52(a).","objectives_minutes":4,"objectives":["Create timely factual records.","Protect confidential information.","Safeguard money and property.","Correct errors without concealing the original record."],
    "lessons":[
      {"title":"Fact, Quote, and Attribution","estimated_minutes":8,"activity_type":"instruction","content":"Document what you observed, what the person said, what someone else reported, what you did, and the outcome. Attribute secondhand information. Avoid motive labels, unsupported diagnosis, copied boilerplate, and vague completion statements. Notes should connect support to the Individual Plan and person's response."},
      {"title":"Timeliness and Corrections","estimated_minutes":8,"activity_type":"instruction","content":"Enter records as close to the event as possible after safety duties. Follow the approved correction and late-entry process; never erase, backdate, overwrite, pre-chart, or share credentials. Preserve electronic audit trails. Report system outages and use only the approved downtime method."},
      {"title":"Minimum Necessary Confidentiality","estimated_minutes":8,"activity_type":"instruction","content":"Access and share private information only for an authorized work purpose. Confirm recipients, use approved channels, protect screens and paper, and avoid public areas, personal devices, and group chats. Handoff the minimum information required for safe continuity, not gossip or unrelated history."},
      {"title":"Funds and Property Controls","estimated_minutes":8,"activity_type":"instruction","content":"Keep money separate, follow authorization, count with required witnesses, record transactions, retain receipts, reconcile, and provide access to the person. Never borrow, pool, substitute, use rewards, or quietly repay a discrepancy. Protect keys, cards, PINs, benefit information, and personal property."},
      {"title":"Audit and Escalation","estimated_minutes":8,"activity_type":"instruction","content":"Reconcile records to source documents and resolve differences transparently. Escalate missing receipts, altered logs, duplicate entries, unexplained balance changes, privacy misdirection, or shared credentials. Correct the system weakness and verify the fix rather than blaming only the last user."}
    ],
    "scenarios":[{"title":"Scenario: Wrong-Recipient Email","estimated_minutes":4,"activity_type":"scenario","content":"A staff member sends a private report to the wrong outside address. Identify containment, notification, preservation, privacy-incident procedure, and why deletion alone is inadequate."},{"title":"Scenario: Cash Does Not Balance","estimated_minutes":4,"activity_type":"scenario","content":"Cash is ten dollars short and one receipt is missing. Preserve the ledger and receipt trail, protect remaining funds, notify, reconcile, and assess incident or exploitation duties."}],
    "source_minutes":3,"source_content":"Primary authority: 55 Pa. Code Sections 6400.22, 6400.50, 6400.213, and 6400.52(a), at https://www.pacodeandbulletin.gov/secure/pacode/data/055/chapter6400/chap6400toc.html. Follow the home's current privacy, records, and funds procedures.","quiz_minutes":5,
    "questions":[
      {"text":"Which documentation entry records facts rather than judgment?","explanation":"Record observable action and direct words. It preserves record integrity, confidentiality, and a traceable audit path for the person's information or funds.","answers":[{"text":"Sam was lazy and did not care about completing the task","correct":false},{"text":"Sam said no and returned to his room","correct":true},{"text":"Sam manipulated staff","correct":false},{"text":"Sam was difficult","correct":false}]},
      {"text":"How should staff create a necessary late documentation entry?","explanation":"Identify it under the approved correction process. It preserves record integrity, confidentiality, and a traceable audit path for the person's information or funds.","answers":[{"text":"Backdated so the entry appears to have been recorded earlier","correct":false},{"text":"Hidden by deleting the original record rather than making an attributable late entry","correct":false},{"text":"Labeled according to procedure","correct":true},{"text":"Copied from a prior entry without confirming the current facts","correct":false}]},
      {"text":"Passwords may be shared when busy:","explanation":"Individual credentials preserve attribution and audit trails; sharing passwords makes it impossible to determine who created or changed a record.","answers":[{"text":"Yes; staff may share credentials whenever workload makes individual login inconvenient","correct":false},{"text":"Share the password only with a trusted coworker on the same shift","correct":false},{"text":"No; every worker must use only their own assigned credentials","correct":true},{"text":"During system outages, even though an approved downtime process exists","correct":false}]},
      {"text":"What does minimum-necessary access mean for confidential records?","explanation":"Use only information needed for an authorized purpose. It preserves record integrity, confidentiality, and a traceable audit path for the person's information or funds.","answers":[{"text":"Share the whole record","correct":false},{"text":"Use only needed information for authorized work","correct":true},{"text":"Use personal chat","correct":false},{"text":"Tell housemates so everyone can help monitor the confidential concern","correct":false}]},
      {"text":"How should staff respond when an individual's cash is missing?","explanation":"Preserve, safeguard, document, and report. It preserves record integrity, confidentiality, and a traceable audit path for the person's information or funds.","answers":[{"text":"Quietly replaced","correct":false},{"text":"Ignored unless the amount is large enough to affect the next audit","correct":false},{"text":"Safeguarded, documented, reconciled, and reported","correct":true},{"text":"Charged to staff","correct":false}]},
      {"text":"Staff may use a person's reward points:","explanation":"The person's benefits and property are protected. It preserves record integrity, confidentiality, and a traceable audit path for the person's information or funds.","answers":[{"text":"Use the reward points for small staff purchases and repay them later","correct":false},{"text":"With verbal staff approval","correct":false},{"text":"No, not for staff benefit","correct":true},{"text":"At the end of the shift, without the person's permission or accounting","correct":false}]},
      {"text":"A wrong-recipient disclosure requires:","explanation":"Follow containment and privacy-incident procedures. It preserves record integrity, confidentiality, and a traceable audit path for the person's information or funds.","answers":[{"text":"Delete the disclosure and do not notify the privacy or security lead","correct":false},{"text":"Containment, notification, preservation, and procedure","correct":true},{"text":"Take no action even though confidential information reached the wrong person","correct":false},{"text":"A public message","correct":false}]},
      {"text":"How should staff classify documentation entered before service occurs?","explanation":"Document only after the service or observation occurs. It preserves record integrity, confidentiality, and a traceable audit path for the person's information or funds.","answers":[{"text":"Efficient because services may be recorded before they actually occur","correct":false},{"text":"Allowed for routines","correct":false},{"text":"Improper because it records services before they actually occur","correct":true},{"text":"Required whenever staff expect the planned service will occur","correct":false}]}
    ]
  },
  {
    "catalog_code":"PA-GH-6400-MED-SAFETY-AWARENESS","title":"Medication Safety Awareness for Chapter 6400 Staff","description":"Awareness training on medication rights, observation, errors, refusals, adverse reactions, and records. It does not authorize medication administration or replace Department-approved training, renewal, practicum, diabetes education, or epinephrine training.","duration_minutes":60,"credit_hours":1.00,"topic_code":"6400.52.JOB_MED_SAFETY","direct_mode":"verified_only","other_mode":"verified_only","citation_note":"55 Pa. Code Sections 6400.161-169 and 6400.52(a); medication administration requires Section 6400.169 qualifications.","objectives_minutes":4,"objectives":["Distinguish awareness from authorization.","Recognize error and adverse-reaction concerns.","Respect refusal and follow prescriber directions.","Protect medication records and promptly escalate."],
    "lessons":[
      {"title":"Authorization Boundary","estimated_minutes":8,"activity_type":"instruction","content":"Only qualified people may administer medication. A staff member who administers under Section 6400.169 needs the Department-approved course and renewals; insulin and epinephrine have added requirements. This module never creates authority. Unqualified staff follow emergency procedure, protect the person, and obtain qualified help without handling medication outside their role."},
      {"title":"Orders, Identity, and the Medication Record","estimated_minutes":8,"activity_type":"instruction","content":"Medication must match the current prescriber order, correct person, medication, dose, time, route, and position where applicable. Never guess from an old label or change an order. Authorized staff compare source information and document after administration, never before. Report discrepancies before proceeding."},
      {"title":"Errors and Omissions","estimated_minutes":8,"activity_type":"instruction","content":"Errors include omitted, wrong, late beyond the defined window, wrong-person, wrong-dose, wrong-route, or wrong-position administration. Protect the person, contact the qualified clinical resource or emergency service as directed, preserve medication and records, and report promptly. Do not conceal by altering the MAR."},
      {"title":"Refusal and Adverse Reaction","estimated_minutes":8,"activity_type":"instruction","content":"A person may refuse. Do not force, hide, or punish. Document refusal and notify the prescriber as directed or when harm may result. Suspected adverse reaction requires immediate practitioner consultation or emergency treatment and documentation of signs, response, and action."},
      {"title":"Storage, Privacy, and Handoff","estimated_minutes":8,"activity_type":"instruction","content":"Keep medications secured, labeled, current, and available only to authorized people. Protect controlled-substance counts and medication records. Handoff current orders, refusals, errors, reactions, and follow-up through approved channels. Report missing keys, damaged storage, missing doses, or count differences immediately."}
    ],
    "scenarios":[{"title":"Scenario: Unfamiliar Loose Tablet","estimated_minutes":4,"activity_type":"scenario","content":"An unqualified staff member finds a loose tablet. Do not administer or guess. Protect access, notify qualified staff, preserve the item, follow error and disposal procedures, and document facts."},{"title":"Scenario: Insulin Request","estimated_minutes":4,"activity_type":"scenario","content":"A trained coworker asks you to give insulin because they are late. Explain the authorization boundary, obtain qualified coverage, protect timing and the person, and escalate rather than administering outside your qualification."}],
    "source_minutes":3,"source_content":"Primary authority: 55 Pa. Code Sections 6400.161-169, especially Section 6400.169 at https://www.pacodeandbulletin.gov/secure/pacode/data/055/chapter6400/s6400.169.html. This course is not Department-approved medication certification, practicum, diabetes education, epinephrine training, or clinical licensure.","quiz_minutes":5,
    "questions":[
      {"text":"Does this course authorize medication administration?","explanation":"Separate Department-approved qualification is required. It preserves the medication record and keeps unqualified staff within the limits of Section 6400.169.","answers":[{"text":"Yes; completing this awareness module authorizes medication administration","correct":false},{"text":"For oral medication","correct":false},{"text":"No; medication authority requires the separate Section 6400.169 qualification","correct":true},{"text":"After two attempts","correct":false}]},
      {"text":"Insulin administration requires:","explanation":"Section 6400.169 requires medication training plus current approved diabetes education.","answers":[{"text":"This awareness module","correct":false},{"text":"Only supervisor permission","correct":false},{"text":"Required medication qualification and approved diabetes education","correct":true},{"text":"A knowledge quiz without the separately required qualification or practicum","correct":false}]},
      {"text":"Medication should be documented:","explanation":"Authorized staff document after administration. It preserves the medication record and keeps unqualified staff within the limits of Section 6400.169.","answers":[{"text":"Before administration, even though the dose may not actually be given","correct":false},{"text":"After administration","correct":true},{"text":"At the end of the week instead of immediately after administration","correct":false},{"text":"Only after errors","correct":false}]},
      {"text":"A medication refusal should be:","explanation":"Respect, document, and notify as directed. It preserves the medication record and keeps unqualified staff within the limits of Section 6400.169.","answers":[{"text":"Punished for refusing medication rather than supported and reported","correct":false},{"text":"Hidden in food to defeat the person's informed medication refusal","correct":false},{"text":"Respected, documented, and reported as directed","correct":true},{"text":"Ignored because refusal does not require support, notification, or documentation","correct":false}]},
      {"text":"A suspected adverse reaction requires:","explanation":"Seek immediate practitioner or emergency guidance. It preserves the medication record and keeps unqualified staff within the limits of Section 6400.169.","answers":[{"text":"Wait until tomorrow","correct":false},{"text":"Immediate consultation or emergency treatment","correct":true},{"text":"Another dose before qualified staff review the suspected reaction","correct":false},{"text":"Delete the medication record so the suspected reaction is hidden","correct":false}]},
      {"text":"A loose unidentified tablet should be:","explanation":"Protect, preserve, notify, and follow procedure. It preserves the medication record and keeps unqualified staff within the limits of Section 6400.169.","answers":[{"text":"Administered despite having no verified identity or authorized order","correct":false},{"text":"Discarded secretly","correct":false},{"text":"Protected and reported under procedure","correct":true},{"text":"Taken home by staff instead of secured and reported through procedure","correct":false}]},
      {"text":"A medication error record may be altered to hide it:","explanation":"Medication records must preserve the original event and correction trail so clinicians and investigators can evaluate the error and protect the person.","answers":[{"text":"Yes; supervisor approval permits staff to conceal a medication error","correct":false},{"text":"With informal supervisor approval to conceal the medication error","correct":false},{"text":"No; the original medication record and correction trail must remain visible","correct":true},{"text":"For late doses, so the medication record does not show the error","correct":false}]},
      {"text":"Who may administer medication under Section 6400.169?","explanation":"Only people qualified under applicable law and Section 6400.169.","answers":[{"text":"Any employee, regardless of medication-administration qualification","correct":false},{"text":"Anyone completing this module","correct":false},{"text":"A properly licensed or qualified person","correct":true},{"text":"Any volunteer, regardless of medication-administration qualification","correct":false}]}
    ]
  },
  {
    "catalog_code":"PA-GH-6400-EMERGENCY-READINESS","title":"General Emergency Readiness and Continuity","description":"Job-skills annual training on hazard recognition, emergency roles, evacuation support, accountability, continuity, and after-action learning. It does not replace verified annual fire-safety or first-aid/CPR training.","duration_minutes":60,"credit_hours":1.00,"topic_code":"6400.52.JOB_EMERGENCY_READINESS","direct_mode":"verified_only","other_mode":"verified_only","citation_note":"55 Pa. Code Sections 6400.46, 6400.103, 6400.145, and 6400.52(a).","objectives_minutes":4,"objectives":["Use all-hazards emergency roles and communication.","Support individual evacuation and accountability.","Maintain medication, records, equipment, and continuity.","Distinguish this module from verified fire and CPR requirements."],
    "lessons":[
      {"title":"All-Hazards Readiness","estimated_minutes":8,"activity_type":"instruction","content":"Prepare for fire, severe weather, utility failure, missing person, medical emergency, unsafe air, flooding, violence, and relocation. Know alarms, exits, shelter locations, emergency numbers, command roles, and backup communication. Personal safety and 911 come before internal notification when danger is immediate."},
      {"title":"Individual Support Needs","estimated_minutes":8,"activity_type":"instruction","content":"Review mobility, communication, sensory, behavioral, medical, supervision, transport, and equipment needs. Assign assistance without assuming a person is helpless. Keep emergency information current and accessible while protecting privacy. Never improvise a transfer or medical procedure beyond training."},
      {"title":"Evacuation, Shelter, and Accountability","estimated_minutes":8,"activity_type":"instruction","content":"Use the correct response for the hazard, move to the designated safe location, account for every person and staff member, communicate missing or injured people, and prevent reentry until authorized. Keep exits clear and avoid elevators or routes prohibited by the plan."},
      {"title":"Continuity of Essential Support","estimated_minutes":8,"activity_type":"instruction","content":"Plan for medications, orders, food and water, power-dependent equipment, chargers, transport, staffing, records, contacts, and accessible communication. Record transfers and handoff. Use approved backup locations and never leave emergency supplies expired or inaccessible."},
      {"title":"Drills and After-Action Improvement","estimated_minutes":8,"activity_type":"instruction","content":"Treat drills as tests, not paperwork. Record response, accountability, barriers, equipment, communication, and individual impact. Correct blocked routes, unclear roles, outdated contacts, or plan gaps and verify the fix. This online module cannot replace expert-origin fire training or in-person CPR skills."}
    ],
    "scenarios":[{"title":"Scenario: Power Failure","estimated_minutes":4,"activity_type":"scenario","content":"A prolonged outage affects refrigerated medication and powered equipment. Apply backup power, clinical consultation, temperature control, communication, relocation thresholds, records, and handoff."},{"title":"Scenario: Evacuation Accountability","estimated_minutes":4,"activity_type":"scenario","content":"At the meeting place one person is unaccounted for. Follow the home's plan, notify emergency responders with last-known facts, maintain group safety, and do not make an unsafe reentry."}],
    "source_minutes":3,"source_content":"Primary authority: 55 Pa. Code Sections 6400.46, 6400.103, 6400.145, and 6400.52(a), at https://www.pacodeandbulletin.gov/secure/pacode/data/055/chapter6400/chap6400toc.html. This course is not the qualified annual fire or first-aid/CPR training.","quiz_minutes":5,
    "questions":[
      {"text":"Immediate danger may require:","explanation":"Call 911 without waiting for routine internal approval. It maintains accountability and continuity without substituting this preparation for required verified skills.","answers":[{"text":"Hold a staff meeting before activating emergency response","correct":false},{"text":"Prompt 911 action","correct":true},{"text":"Next-shift review","correct":false},{"text":"Consult the written plan before checking whether anyone is in danger","correct":false}]},
      {"text":"Emergency plans should include:","explanation":"Address individual mobility, communication, health, and support needs.","answers":[{"text":"Only the address","correct":false},{"text":"Individual support and evacuation needs","correct":true},{"text":"Only staff names","correct":false},{"text":"Marketing contacts","correct":false}]},
      {"text":"After evacuation staff should:","explanation":"Account and report missing or injured people. It maintains accountability and continuity without substituting this preparation for required verified skills.","answers":[{"text":"Reenter immediately","correct":false},{"text":"Account for everyone at the safe location","correct":true},{"text":"Leave separately","correct":false},{"text":"Ignore the roster","correct":false}]},
      {"text":"Power-dependent equipment requires:","explanation":"Use the current backup and relocation plan. It maintains accountability and continuity without substituting this preparation for required verified skills.","answers":[{"text":"No backup planning because power failures are assumed to be brief","correct":false},{"text":"Backup power and relocation contingencies","correct":true},{"text":"A personal extension cord only","correct":false},{"text":"Delayed notice after equipment failure has already created an emergency","correct":false}]},
      {"text":"An unsafe reentry should be made to search alone:","explanation":"Give responders last-known facts; do not create another victim.","answers":[{"text":"Always; staff must reenter alone even when authorities say it is unsafe","correct":false},{"text":"For retrieving belongings even though the structure is unsafe","correct":false},{"text":"No; staff wait until emergency authorities declare reentry safe","correct":true},{"text":"After five minutes","correct":false}]},
      {"text":"When is an emergency drill fully complete?","explanation":"Review performance and verify corrections, not merely sign attendance.","answers":[{"text":"Attendance is signed","correct":false},{"text":"Performance is reviewed and gaps corrected","correct":true},{"text":"No one discusses it","correct":false},{"text":"As soon as the alarm stops, even if accountability is unfinished","correct":false}]},
      {"text":"Does this module replace annual fire training?","explanation":"Section 6400.46 requires verified expert-origin fire instruction.","answers":[{"text":"Yes; a general emergency module replaces home-specific annual fire training","correct":false},{"text":"Yes for supervisors, even without home-specific annual fire verification","correct":false},{"text":"No; general readiness does not replace annual verified fire-safety training","correct":true},{"text":"Only after the learner renews the same online completion","correct":false}]},
      {"text":"Emergency records should travel through:","explanation":"Use authorized secure continuity procedures. It maintains accountability and continuity without substituting this preparation for required verified skills.","answers":[{"text":"Public social media","correct":false},{"text":"Approved secure handoff","correct":true},{"text":"Personal phone photos sent through a staff group message","correct":false},{"text":"Unencrypted group chat","correct":false}]}
    ]
  },
  {
    "catalog_code":"PA-GH-6400-PERSON-BEHAVIOR-SUPPORT","title":"Preparation for Facilitated Behavior Support Verification","description":"Preparation for a facilitated, person-specific annual verification of the current behavior-support component, communication, prevention, approved techniques, crisis response, and documentation. A learner completion certificate records preparation only; the home must separately verify live training by a person knowledgeable about the current plan.","duration_minutes":120,"credit_hours":2.00,"topic_code":"6400.52.C5.PERSON_BEHAVIOR_SUPPORT","direct_mode":"verified_only","other_mode":"verified_only","citation_note":"55 Pa. Code Sections 6400.52(c)(5) and 6400.196; DHS guidance says this topic cannot be web-only and must be person-specific and current-plan based.","objectives_minutes":5,"objectives":["Explain the person's current behavior-support procedures.","Identify communication, prevention, triggers, early signs, and approved responses.","Demonstrate assigned techniques with a qualified facilitator.","Document implementation and report plan drift."],
    "lessons":[
      {"title":"Verification and Current-Plan Gate","estimated_minutes":18,"activity_type":"practice","content":"The facilitator confirms the person, current assessment and plan dates, staff assignment, trainer knowledge, and procedures to be taught. Generic online material cannot satisfy this course. Review privacy and use only authorized person-specific information. If the plan is unavailable, expired, or inconsistent with practice, stop and obtain the current approved version before credit."},
      {"title":"Communication and Function","estimated_minutes":18,"activity_type":"practice","content":"Learn how the person communicates comfort, refusal, pain, fear, overload, choice, and need for space. Review known antecedents, setting events, early signs, likely function, strengths, preferred regulation, and successful replacement skills. Do not label behavior as attention-seeking or manipulative without plan-based functional understanding."},
      {"title":"Prevention and Trauma-Informed Support","estimated_minutes":18,"activity_type":"practice","content":"Practice the person's proactive supports: predictable information, meaningful choice, communication access, environmental adjustment, relationship approach, skill teaching, reinforcement, medical checks, and pacing. Use calm, respectful, least restrictive responses. Never use punishment, humiliation, coercion, or a procedure absent from the plan."},
      {"title":"Approved Response and Demonstration","estimated_minutes":18,"activity_type":"practice","content":"The facilitator models and observes each technique assigned to staff, including decision points, prohibited actions, release or stop criteria, emergency contacts, and post-event support. Staff ask questions and demonstrate competency. If physical restraint is used, Section 6400.196 requires the implementer to experience its use directly; an online attestation cannot document that requirement."},
      {"title":"Documentation, Debrief, and Change","estimated_minutes":15,"activity_type":"practice","content":"Record antecedents, observable behavior, support used, timing, response, injury or health concern, notifications, and outcome. Debrief respectfully with the person as appropriate. Report new patterns, ineffective techniques, side effects, rights concerns, or mismatch with the current plan so qualified team members can review rather than allowing informal drift."}
    ],
    "scenarios":[{"title":"Facilitated Scenario: Escalating Noise Distress","estimated_minutes":8,"activity_type":"practice","content":"Using the actual plan, demonstrate how staff recognize early signs, reduce noise, offer the person's communication and regulation options, preserve choice, and escalate only through approved steps. The facilitator records competency and coaching."},{"title":"Facilitated Scenario: Unlisted Technique","estimated_minutes":8,"activity_type":"practice","content":"A coworker recommends a technique that appears effective but is absent from the current plan. Practice protecting the person, declining unauthorized use, notifying the right role, documenting facts, and requesting plan review."}],
    "source_minutes":4,"source_content":"Primary authority: 55 Pa. Code Sections 6400.52(c)(5) and 6400.196 at https://www.pacodeandbulletin.gov/secure/pacode/data/055/chapter6400/s6400.196.html, plus the DHS Chapter 6400 Compliance Guide. Credit requires verified person-specific facilitated training and competency evidence.","quiz_minutes":8,
    "questions":[
      {"text":"Can web-only review satisfy this course?","explanation":"DHS guidance requires person-specific, non-web-only training.","answers":[{"text":"Yes; an online page review alone verifies person-specific behavior procedures","correct":false},{"text":"For experienced staff","correct":false},{"text":"No; a knowledgeable facilitator must verify current person-specific procedures","correct":true},{"text":"After two quizzes","correct":false}]},
      {"text":"Which source must person-specific behavior-support training use?","explanation":"Use the person's current assessment and plan. It keeps intervention person-specific, least restrictive, and tied to the current authorized behavior-support plan.","answers":[{"text":"A generic plan that is not the person's current authorized plan","correct":false},{"text":"An expired plan that no longer reflects current approved procedures","correct":false},{"text":"The current person-specific plan","correct":true},{"text":"A coworker's memory of an earlier version of the person's plan","correct":false}]},
      {"text":"An unlisted technique should be:","explanation":"Do not improvise; request qualified review. It keeps intervention person-specific, least restrictive, and tied to the current authorized behavior-support plan.","answers":[{"text":"Tried once without authorization to see whether it changes behavior","correct":false},{"text":"Used secretly so supervisors and the plan team cannot review it","correct":false},{"text":"Declined and referred for plan review","correct":true},{"text":"Added by shift staff","correct":false}]},
      {"text":"Prevention should emphasize:","explanation":"Communication, choice, environment, and skill support are proactive.","answers":[{"text":"Punishment intended to suppress behavior rather than prevent its causes","correct":false},{"text":"Communication, choice, and proactive support","correct":true},{"text":"Threats intended to obtain compliance through fear or coercion","correct":false},{"text":"Humiliation intended to force compliance with staff expectations","correct":false}]},
      {"text":"Physical-restraint implementers must:","explanation":"Section 6400.196 includes direct experience when restraint is used.","answers":[{"text":"Watch a slide without demonstrating the authorized physical technique","correct":false},{"text":"Read a memo without demonstrating the authorized restraint procedure","correct":false},{"text":"Meet the plan-specific direct-experience requirement","correct":true},{"text":"Sign without practice","correct":false}]},
      {"text":"Behavior documentation should include:","explanation":"Record observable antecedent, support, response, and outcome.","answers":[{"text":"Motive labels that assume why the person acted without evidence","correct":false},{"text":"Observable facts, support used, response, and outcome","correct":true},{"text":"Rumors from uninvolved staff instead of direct observations or quotes","correct":false},{"text":"Only a diagnosis","correct":false}]},
      {"text":"How should staff respond when practice drifts from the approved plan?","explanation":"A mismatch between practice and the current behavior-support plan must be reported for qualified review; staff may not normalize or copy unauthorized procedures.","answers":[{"text":"Normalized as routine even though practice differs from the approved plan","correct":false},{"text":"Hidden from the qualified reviewer so the unapproved practice can continue","correct":false},{"text":"Reported and reviewed","correct":true},{"text":"Copied into future shifts without qualified review or authorization","correct":false}]},
      {"text":"Who may verify person-specific behavior-support competency?","explanation":"A knowledgeable facilitator observes assigned techniques. It keeps intervention person-specific, least restrictive, and tied to the current authorized behavior-support plan.","answers":[{"text":"The learner alone","correct":false},{"text":"Any roommate, even without authorization or subject knowledge","correct":false},{"text":"A knowledgeable authorized facilitator","correct":true},{"text":"An LMS completion timer with no qualified expert-originated material","correct":false}]}
    ]
  },
  {
    "catalog_code":"PA-GH-6400-PERSON-IP-IMPLEMENTATION","title":"Preparation for Facilitated Individual Plan Verification","description":"Preparation for facilitated person-specific annual verification using the current assessment and Individual Plan, health and safety procedures, communication, goals, choice, documentation, and handoff. A learner completion certificate records preparation only; verified credit requires the live current-plan lab.","duration_minutes":120,"credit_hours":2.00,"topic_code":"6400.52.C6.PERSON_IP_IMPLEMENTATION","direct_mode":"verified_only","other_mode":"verified_only","citation_note":"55 Pa. Code Sections 6400.186 and 6400.52(c)(6); DHS guidance requires current person-specific, non-web-only training.","objectives_minutes":5,"objectives":["Locate and explain the current assessment and Individual Plan.","Demonstrate assigned health, safety, communication, and support procedures.","Connect daily support and records to goals and choice.","Escalate missing, conflicting, or outdated instructions."],
    "lessons":[
      {"title":"Current Documents and Staff Assignment","estimated_minutes":18,"activity_type":"practice","content":"The facilitator verifies current assessment, Individual Plan, revisions, healthcare orders, emergency procedures, communication profile, and staff assignment. Staff identify what applies on their shift and where authorized records are found. Training pauses when a critical document is missing or inconsistent."},
      {"title":"What Matters and How the Person Communicates","estimated_minutes":18,"activity_type":"practice","content":"Review strengths, preferences, relationships, routines, culture, communication signals, decision support, goals, and distress indicators. Demonstrate how the person expresses yes, no, pain, help, and emergency needs. Staff must not treat behavior or limited speech as absence of preference."},
      {"title":"Health, Safety, and Emergency Procedures","estimated_minutes":18,"activity_type":"practice","content":"A knowledgeable facilitator demonstrates person-specific eating, positioning, transfer, skin, respiratory, mobility, supervision, emergency, equipment, and other assigned procedures. Staff practice only within their role and competency. Orders and plans control; no one copies another person's procedure."},
      {"title":"Goal Support, Choice, and Community Practice","estimated_minutes":18,"activity_type":"practice","content":"Translate each assigned outcome into observable opportunity, staff action, cueing level, data, and the person's response. Practice offering real choices and fading support when safe. Avoid doing tasks for the person merely to save time or recording attendance as goal progress."},
      {"title":"Documentation, Handoff, and Plan Feedback","estimated_minutes":15,"activity_type":"practice","content":"Record opportunity, support, participation, response, progress, refusal, health change, and follow-up. Handoff unresolved risks and appointments. Report contradictory, outdated, ineffective, or overly restrictive instructions to the responsible plan role; staff implement current authorized revisions rather than editing plans informally."}
    ],
    "scenarios":[{"title":"Practice: Safe Eating and Choice","estimated_minutes":8,"activity_type":"practice","content":"Using the actual plan, demonstrate texture, positioning, pacing, supervision, communication, refusal response, emergency action, and documentation. The facilitator records competency and correction."},{"title":"Practice: Conflicting Instructions","estimated_minutes":8,"activity_type":"practice","content":"The plan and a shift note conflict about transfer support. Practice protecting the person, stopping unsafe improvisation, obtaining qualified clarification, preserving records, and completing handoff."}],
    "source_minutes":4,"source_content":"Primary authority: 55 Pa. Code Sections 6400.186 and 6400.52(c)(6), official Chapter 6400 at https://www.pacodeandbulletin.gov/secure/pacode/data/055/chapter6400/s6400.186.html, and DHS guidance. Credit requires verified current-person training and competency evidence.","quiz_minutes":8,
    "questions":[
      {"text":"Can a generic online course satisfy this topic?","explanation":"Section 6400.52(c)(6) training must use the current assessment and Individual Plan; generic online content cannot verify person-specific competence.","answers":[{"text":"Yes; generic online content alone satisfies current person-specific plan training","correct":false},{"text":"Yes for supervisors, even without current person-specific facilitated training","correct":false},{"text":"No; Section 6400.52(c)(6) requires current person-specific facilitated training","correct":true},{"text":"Only after the learner renews the same online completion","correct":false}]},
      {"text":"If critical documents conflict, staff should:","explanation":"Protect safety and obtain qualified clarification. It prevents staff from improvising and ensures support follows the person's current assessment and Individual Plan.","answers":[{"text":"Choose whichever instruction seems easiest and ignore the conflict","correct":false},{"text":"Improvise a procedure that does not appear in either current document","correct":false},{"text":"Pause unsafe action and seek clarification","correct":true},{"text":"Copy another plan","correct":false}]},
      {"text":"Person-specific procedures may be copied from another person:","explanation":"Eating, transfer, respiratory, and other safety procedures are individualized; copying them can expose both people to serious harm.","answers":[{"text":"Always; one person's procedure may be copied whenever staff find it efficient","correct":false},{"text":"If diagnoses match","correct":false},{"text":"No; each procedure must come from the person's own current plan","correct":true},{"text":"On night shift, when fewer supervisors are present to notice the copying","correct":false}]},
      {"text":"Goal documentation should show:","explanation":"Record opportunity, support, participation, and response. It prevents staff from improvising and ensures support follows the person's current assessment and Individual Plan.","answers":[{"text":"Attendance alone without the person's response or observable progress","correct":false},{"text":"Opportunity, support, participation, and response","correct":true},{"text":"Staff opinion about progress without observable evidence or the person's response","correct":false},{"text":"A copied phrase that does not describe the person's response","correct":false}]},
      {"text":"Who may edit the plan informally?","explanation":"Only authorized planning processes revise it. It prevents staff from improvising and ensures support follows the person's current assessment and Individual Plan.","answers":[{"text":"Any staff member informally, without the authorized planning process","correct":false},{"text":"The oldest employee","correct":false},{"text":"No one outside the authorized process","correct":true},{"text":"A roommate who has no authority to revise the Individual Plan","correct":false}]},
      {"text":"The person's no may be communicated by:","explanation":"Use the person's actual communication method. It prevents staff from improvising and ensures support follows the person's current assessment and Individual Plan.","answers":[{"text":"Speech only, excluding gestures, behavior, devices, or other communication","correct":false},{"text":"Any established communication signal","correct":true},{"text":"A staff vote that replaces the person's own communication and choice","correct":false},{"text":"A diagnosis assigned by staff rather than the person's communication","correct":false}]},
      {"text":"Staff practice procedures:","explanation":"Practice only assigned procedures within role and competency.","answers":[{"text":"Beyond their role","correct":false},{"text":"Within assigned role and competency","correct":true},{"text":"Without a facilitator","correct":false},{"text":"From memory only","correct":false}]},
      {"text":"What evidence is required for person-specific training credit?","explanation":"The home verifies current plan review and competency. It prevents staff from improvising and ensures support follows the person's current assessment and Individual Plan.","answers":[{"text":"Elapsed page-open time without person-specific facilitated verification","correct":false},{"text":"A learner attestation alone","correct":false},{"text":"Verified person-specific facilitated training","correct":true},{"text":"A generic certificate","correct":false}]}
    ]
  },
  {
    "catalog_code":"PA-GH-6400-FIRE-SAFETY-VERIFIED","title":"Preparation for Onsite Fire Safety Verification","description":"Preparation for qualified fire-safety training and home-specific evacuation practice under Section 6400.46. A learner completion certificate records preparation only; the LMS cannot certify the expert, facilitator, current materials, or site-specific practice.","duration_minutes":60,"credit_hours":1.00,"topic_code":"6400.46.FIRE_SAFETY","direct_mode":"verified_only","other_mode":"verified_only","citation_note":"55 Pa. Code Section 6400.46(a)-(b) and DHS guidance on qualified expert origin, trained agency facilitators, current materials, and site-specific supplementation.","objectives_minutes":4,"objectives":["Explain prevention, detection, notification, and extinguisher boundaries.","Demonstrate the home's routes, meeting place, and accountability.","State drill responsibilities and smoking controls.","Document qualified source and site-specific completion."],
    "lessons":[
      {"title":"Qualified Source Gate","estimated_minutes":8,"activity_type":"practice","content":"The home verifies the fire-safety expert or agency facilitator trained by an expert, material date, training date, attendees, and length. Expert-produced video may support training when current, but the home's evacuation routes and meeting place must still be taught. Online completion alone earns no credit."},
      {"title":"Prevention and Detection","estimated_minutes":8,"activity_type":"practice","content":"Review ignition sources, electrical and cooking safety, smoking procedure when applicable, clear exits, doors, alarms, smoke detectors, and reporting of defects. Never disable an alarm or block an exit. Practice identifying hazards in the actual home."},
      {"title":"Alarm, Notification, and Extinguisher Limits","estimated_minutes":8,"activity_type":"practice","content":"Raise alarm, notify the fire department promptly, and prioritize evacuation. Use an extinguisher only when trained, safe, with a clear exit, and consistent with the plan; never delay evacuation or fight a spreading fire. Review actual alarm and extinguisher locations."},
      {"title":"Home-Specific Evacuation","estimated_minutes":8,"activity_type":"practice","content":"Walk primary and alternate routes, fire-safe areas if applicable, assistance assignments, mobility and communication supports, designated meeting place, and reentry prohibition. Account for everyone and immediately tell responders who is missing and last known location."},
      {"title":"Drill Roles and Verification","estimated_minutes":8,"activity_type":"practice","content":"Demonstrate responsibilities during drills without unsafe shortcuts. Record source, content, date, length, attendance, site-specific practice, and certificate where issued. Correct route, alarm, staffing, or accountability gaps and verify the repair."}
    ],
    "scenarios":[{"title":"Practice: Blocked Primary Exit","estimated_minutes":4,"activity_type":"practice","content":"Use the actual alternate route, assistance assignments, alarm and notification, meeting place, and accountability; report and correct the obstruction."},{"title":"Practice: Missing at Meeting Place","estimated_minutes":4,"activity_type":"practice","content":"Maintain group safety, notify responders with the person's identity and last-known location, follow the home's accountability procedure, and do not reenter an unsafe building."}],
    "source_minutes":3,"source_content":"Primary authority: 55 Pa. Code Section 6400.46 at https://www.pacodeandbulletin.gov/secure/pacode/data/055/chapter6400/s6400.46.html and the DHS Chapter 6400 Compliance Guide. Verified qualified-source and home-specific evidence is mandatory.","quiz_minutes":5,
    "questions":[
      {"text":"Credit may be earned by web review alone?","explanation":"Qualified-source and site-specific verification are required.","answers":[{"text":"Yes; web review alone earns fire-safety credit without qualified or onsite verification","correct":false},{"text":"For experienced staff, even without current site-specific verification","correct":false},{"text":"No; qualified-source and home-specific fire-safety verification is required","correct":true},{"text":"After two video views without qualified-source or onsite verification","correct":false}]},
      {"text":"Generic video must be supplemented with:","explanation":"Teach the actual routes and meeting place. It prioritizes evacuation and verified site-specific instruction from a qualified fire-safety source.","answers":[{"text":"A general fire-prevention handout that omits the home's evacuation routes","correct":false},{"text":"Home-specific evacuation information","correct":true},{"text":"A facility emergency policy that does not identify this home's exits","correct":false},{"text":"A comprehension survey without onsite route or meeting-place instruction","correct":false}]},
      {"text":"Fire-department notification should occur:","explanation":"Section 6400.46 requires notification of the local fire department as soon as possible after discovery; cleanup or internal review must not delay the call.","answers":[{"text":"Only after cleanup, even though the required notification is urgent","correct":false},{"text":"As soon as possible","correct":true},{"text":"The next day, even though notification is required as soon as possible","correct":false},{"text":"Only after staff reenter the building and complete an inspection","correct":false}]},
      {"text":"An extinguisher should delay evacuation:","explanation":"An extinguisher is used only within training and with a clear exit; it must never delay evacuation or place staff between the fire and escape.","answers":[{"text":"Always; staff should attempt extinguisher use before starting evacuation","correct":false},{"text":"For smoke, even when evacuation is already underway","correct":false},{"text":"No; evacuation takes priority over optional extinguisher use","correct":true},{"text":"For retrieving belongings even though the structure is unsafe","correct":false}]},
      {"text":"At the meeting place staff must:","explanation":"Account and notify responders of missing people. It prioritizes evacuation and verified site-specific instruction from a qualified fire-safety source.","answers":[{"text":"Disperse before accounting confirms that everyone reached the meeting place","correct":false},{"text":"Account for everyone","correct":true},{"text":"Reenter the unsafe building before emergency personnel authorize it","correct":false},{"text":"Turn off the alarms before completing accountability","correct":false}]},
      {"text":"How should staff respond after finding a blocked exit?","explanation":"Use alternate route and correct the hazard. It prioritizes evacuation and verified site-specific instruction from a qualified fire-safety source.","answers":[{"text":"Ignored until the next scheduled fire-safety inspection","correct":false},{"text":"Used anyway despite the known obstruction and evacuation risk","correct":false},{"text":"Reported and corrected","correct":true},{"text":"Hidden from residents and inspectors while staff continue using the route","correct":false}]},
      {"text":"Fire training records include:","explanation":"A defensible fire-training record identifies the qualified source, content, date, actual length, attendees, home-specific practice, and completion evidence.","answers":[{"text":"Attendance alone without source, length, or site-specific evidence","correct":false},{"text":"Source, content, date, length, attendees, and evidence","correct":true},{"text":"A quiz score without required qualified-source and site-specific evidence","correct":false},{"text":"The course title only, with no source, date, length, or attendance evidence","correct":false}]},
      {"text":"Who may originate required training?","explanation":"A qualified fire-safety expert; trained agency personnel may facilitate per DHS guidance.","answers":[{"text":"An experienced employee who lacks qualified fire-safety expert status","correct":false},{"text":"A qualified expert or properly expert-trained facilitator","correct":true},{"text":"An LMS timer without a qualified person's review or verification","correct":false},{"text":"Any vendor claim","correct":false}]}
    ]
  },
  {
    "catalog_code":"PA-GH-6400-FIRST-AID-CPR-VERIFIED","title":"Preparation for First Aid, Heimlich, and CPR Skills Verification","description":"Preparation for trainer-led first aid, choking-response, and CPR skills under Section 6400.46(d). A learner completion certificate records preparation only; verified credit requires an eligible certified trainer and in-person skills, and PennTrain does not issue clinical certification.","duration_minutes":180,"credit_hours":3.00,"topic_code":"6400.46.FIRST_AID_CPR","direct_mode":"verified_only","other_mode":"verified_only","citation_note":"55 Pa. Code Section 6400.46(c)-(d) and DHS guidance: eligible certified trainer, annual timing, and an in-person component.","objectives_minutes":10,"objectives":["Use scene safety and emergency activation.","Demonstrate trainer-approved first-aid steps.","Demonstrate choking response and CPR on training equipment.","Document trainer eligibility, in-person skill verification, date, and actual length."],
    "lessons":[
      {"title":"Trainer and In-Person Gate","estimated_minutes":30,"activity_type":"practice","content":"Verify the trainer is certified by a hospital or recognized healthcare organization, the curriculum is current, and an in-person component occurs. Record certification evidence, date, content, length, attendees, and skill result. A valid multi-year staff certification may affect repetition under DHS guidance, but the home verifies applicability. Online completion alone earns nothing."},
      {"title":"Scene Safety and First Assessment","estimated_minutes":30,"activity_type":"practice","content":"With the trainer, practice scene safety, protective equipment, responsiveness, breathing assessment, emergency activation, and use of the person's emergency information. Provide only trained care. Review urgent illness, bleeding, burns, cuts, stings, sprains, strains, and shock within the selected recognized curriculum."},
      {"title":"First-Aid Skill Stations","estimated_minutes":30,"activity_type":"practice","content":"Rotate through trainer-led stations for bleeding control, basic wound and burn response, positioning within training, and scenario communication. Demonstrate infection precautions, when not to move a person, and when to call 911. The trainer corrects technique and records competency."},
      {"title":"Choking and Heimlich Techniques","estimated_minutes":30,"activity_type":"practice","content":"Practice recognition of mild and severe airway obstruction and the curriculum's age- and body-appropriate response on approved equipment. Activate emergency services at the required point, transition when responsiveness changes, and obtain follow-up. Never practice thrusts on an actual learner."},
      {"title":"CPR and Integrated Response","estimated_minutes":25,"activity_type":"practice","content":"Demonstrate CPR sequence, compressions, breaths if included, AED use, team role changes, and continued care until relieved, using approved equipment and trainer feedback. Integrate choking-to-unresponsiveness and individual emergency information. This LMS quiz never replaces observed skill performance."}
    ],
    "scenarios":[{"title":"Skill Scenario: Unresponsive Person","estimated_minutes":7,"activity_type":"practice","content":"Complete the recognized curriculum sequence for scene safety, responsiveness, emergency activation, CPR, AED, teamwork, and handoff while the trainer observes."},{"title":"Skill Scenario: Severe Choking","estimated_minutes":7,"activity_type":"practice","content":"Recognize severe obstruction, perform the trainer-approved sequence on equipment, activate emergency response, and transition appropriately if responsiveness changes."}],
    "source_minutes":5,"source_content":"Primary authority: 55 Pa. Code Section 6400.46(c)-(d) at https://www.pacodeandbulletin.gov/secure/pacode/data/055/chapter6400/s6400.46.html and the DHS Chapter 6400 Compliance Guide. Credit requires eligible trainer evidence and observed in-person skills; actual provider curriculum controls technique.","quiz_minutes":6,
    "questions":[
      {"text":"Can online review alone satisfy this course?","explanation":"An in-person component and eligible trainer are required. It requires observed in-person performance under an eligible trainer rather than relying on online knowledge alone.","answers":[{"text":"Yes; an online review alone proves first-aid, choking, and CPR skill competency","correct":false},{"text":"For renewal courses, even when live skills must still be demonstrated","correct":false},{"text":"No; an eligible trainer must provide the required in-person component","correct":true},{"text":"After an online exam even though no live skill verification occurred","correct":false}]},
      {"text":"The trainer must be certified by:","explanation":"Section 6400.46 names a hospital or recognized healthcare organization.","answers":[{"text":"An employer-designated trainer who lacks recognized healthcare certification","correct":false},{"text":"A hospital or recognized healthcare organization","correct":true},{"text":"A coworker selected only because they previously attended the course","correct":false},{"text":"A software vendor","correct":false}]},
      {"text":"First action at an emergency scene is:","explanation":"Assess scene safety before entering danger. It requires observed in-person performance under an eligible trainer rather than relying on online knowledge alone.","answers":[{"text":"Begin incident paperwork before checking scene safety","correct":false},{"text":"Check scene safety","correct":true},{"text":"Move every injured person before checking hazards or condition","correct":false},{"text":"Wait alone without checking scene safety or activating trained help","correct":false}]},
      {"text":"Severe choking skills should be practiced on:","explanation":"Use approved training equipment, not actual thrusts on a learner.","answers":[{"text":"An actual learner","correct":false},{"text":"Approved training equipment","correct":true},{"text":"A resident or coworker instead of approved training equipment","correct":false},{"text":"No training equipment, using only a verbal description of the skill","correct":false}]},
      {"text":"What evidence is required to verify CPR competency?","explanation":"Section 6400.46(d) requires an in-person component, so a qualified trainer must observe the learner performing the required skills.","answers":[{"text":"An LMS page timer without observed performance by a qualified trainer","correct":false},{"text":"Observed in-person skill performance","correct":true},{"text":"A reading log without observed CPR skill performance","correct":false},{"text":"A signature only","correct":false}]},
      {"text":"Emergency services should be activated:","explanation":"Follow the recognized curriculum and person's emergency procedure promptly.","answers":[{"text":"After the shift, even when emergency services are needed immediately","correct":false},{"text":"At the point required by the recognized response sequence","correct":true},{"text":"Only by management","correct":false},{"text":"Only after staff finish routine incident paperwork","correct":false}]},
      {"text":"PennTrain issues clinical certification through this module:","explanation":"It records verified external/facilitated evidence; it is not the certifier.","answers":[{"text":"Yes; PennTrain completion itself is a recognized clinical certification","correct":false},{"text":"Yes, but only for CPR and without an eligible external trainer","correct":false},{"text":"No; PennTrain records preparation and evidence but does not clinically certify","correct":true},{"text":"For first aid only","correct":false}]},
      {"text":"Training records must include:","explanation":"Document trainer/source, date, content, length, attendance, and skill evidence.","answers":[{"text":"A quiz score without trainer eligibility or observed skill evidence","correct":false},{"text":"Trainer/source, date, content, length, attendance, and skill evidence","correct":true},{"text":"Course title only","correct":false},{"text":"A verbal statement only","correct":false}]}
    ]
  }
]
$catalog$::jsonb;
  v_item jsonb;
  v_lesson jsonb;
  v_scenario jsonb;
  v_question jsonb;
  v_answer jsonb;
  v_course_id uuid;
  v_version_id uuid;
  v_block_id uuid;
  v_quiz_id uuid;
  v_question_id uuid;
  v_direct_type_id uuid;
  v_other_type_id uuid;
  v_sort integer;
  v_answer_sort integer;
  v_total integer;
  v_correct integer;
  v_archived_count integer;
  v_objectives_text text;
  v_existing_codes text;
  v_applied_prompt text;
  v_instruction_prompt text;
begin
  select string_agg(c.catalog_code, ', ' order by c.catalog_code)
  into v_existing_codes
  from public.courses c
  where c.organization_id is null
    and c.catalog_code in (
    select item ->> 'catalog_code'
    from jsonb_array_elements(v_catalog) item
  );

  if v_existing_codes is not null then
    raise exception 'Chapter 6400 catalog seed refused because catalog code(s) already exist: %',
      v_existing_codes using errcode = 'unique_violation';
  end if;

  select tt.id into v_direct_type_id
  from public.training_types tt
  where tt.organization_id is null and tt.code = 'GH-DIRECT-ANNUAL' and tt.is_active
  order by tt.is_system_default desc, tt.created_at, tt.id limit 1;

  select tt.id into v_other_type_id
  from public.training_types tt
  where tt.organization_id is null and tt.code = 'GH-OTHER-ANNUAL' and tt.is_active
  order by tt.is_system_default desc, tt.created_at, tt.id limit 1;

  if v_direct_type_id is null or v_other_type_id is null then
    raise exception 'Active system training types GH-DIRECT-ANNUAL and GH-OTHER-ANNUAL are required';
  end if;

  -- Retire the aggregate from future discovery while retaining its system
  -- training-type bridge so already-open historical assignments keep their
  -- original completion behavior.
  perform set_config('app.privileged_write', 'on', true);
  update public.courses
  set status = 'archived', updated_at = now()
  where organization_id is null
    and catalog_code is null
    and training_type_id = v_direct_type_id;
  get diagnostics v_archived_count = row_count;
  if v_archived_count <> 1 then
    raise exception 'Expected exactly one legacy system GH-DIRECT-ANNUAL aggregate course to archive; found %',
      v_archived_count;
  end if;
  perform set_config('app.privileged_write', 'off', true);

  for v_item in select value from jsonb_array_elements(v_catalog)
  loop
    v_total := (v_item ->> 'objectives_minutes')::integer
      + (select coalesce(sum((x ->> 'estimated_minutes')::integer), 0)
         from jsonb_array_elements(v_item -> 'lessons') x)
      + (select coalesce(sum((x ->> 'estimated_minutes')::integer), 0)
         from jsonb_array_elements(v_item -> 'scenarios') x)
      + (v_item ->> 'source_minutes')::integer
      + (v_item ->> 'quiz_minutes')::integer;

    if v_total <> (v_item ->> 'duration_minutes')::integer then
      raise exception 'Course % block minutes % do not equal declared duration %',
        v_item ->> 'catalog_code', v_total, v_item ->> 'duration_minutes';
    end if;

    if jsonb_array_length(v_item -> 'lessons') + 1 not between 4 and 7 then
      raise exception 'Course % must have 4-7 instructional blocks including objectives',
        v_item ->> 'catalog_code';
    end if;
    if jsonb_array_length(v_item -> 'scenarios') < 2 then
      raise exception 'Course % must have at least two scenarios/practices', v_item ->> 'catalog_code';
    end if;
    if jsonb_array_length(v_item -> 'questions') not between 8 and 12 then
      raise exception 'Course % must have 8-12 final questions', v_item ->> 'catalog_code';
    end if;

    for v_question in select value from jsonb_array_elements(v_item -> 'questions')
    loop
      select count(*) filter (where (a ->> 'correct')::boolean)
      into v_correct from jsonb_array_elements(v_question -> 'answers') a;
      if jsonb_array_length(v_question -> 'answers') <> 4 or v_correct <> 1
         or length(btrim(v_question ->> 'text')) < 25
         or length(btrim(v_question ->> 'explanation')) < 60
         or exists (
           select 1
           from jsonb_array_elements(v_question -> 'answers') answer_item
           where length(btrim(answer_item ->> 'text')) < 15
         ) then
        raise exception 'Invalid four-answer key or explanation in course % question %',
          v_item ->> 'catalog_code', v_question ->> 'text';
      end if;
    end loop;

    insert into public.courses (
      organization_id, catalog_code, title, description, category, status,
      estimated_duration_minutes, recurrence_interval_days
    ) values (
      null, v_item ->> 'catalog_code', v_item ->> 'title', v_item ->> 'description',
      'Pennsylvania Chapter 6400', 'draft',
      (v_item ->> 'duration_minutes')::integer, 365
    ) returning id into v_course_id;

    insert into public.course_versions (
      course_id, organization_id, version_number, title, description,
      status, published_at, content_standard
    ) values (
      v_course_id, null, 1, v_item ->> 'title', v_item ->> 'description',
      'draft', null, 'comprehensive'
    ) returning id into v_version_id;

    select string_agg('- ' || value, E'\n') into v_objectives_text
    from jsonb_array_elements_text(v_item -> 'objectives');

    v_sort := 1;
    insert into public.course_blocks (
      course_version_id, organization_id, block_type, sort_order, title, body
    ) values (
      v_version_id, null, 'text', v_sort, 'Learning Objectives and Scope',
      jsonb_build_object(
        'content', 'By the end of this course, the learner will be able to:' || E'\n' || v_objectives_text,
        'estimated_minutes', (v_item ->> 'objectives_minutes')::integer,
        'activity_type', 'objectives'
      )
    );

    for v_lesson in select value from jsonb_array_elements(v_item -> 'lessons')
    loop
      v_applied_prompt := case when v_lesson ->> 'activity_type' = 'practice' then
        E'\n\nLearner work product: In your response, name the current person-specific plan, home procedure, or qualified curriculum used for this practice. List the steps you personally demonstrated in order; the safety, privacy, choice, and stop conditions you checked; the facilitator or qualified reviewer who observed you; the feedback or correction you received; and the evidence the home should retain. Do not copy identifying information into the training response. If the required source, equipment, facilitator, or authorization is missing, record that gap and the escalation needed before credit.'
        else ''
      end;
      v_instruction_prompt := case
        when v_lesson ->> 'activity_type' = 'practice' then ''
        when v_item ->> 'catalog_code' in (
          'PA-GH-6400-RIGHTS-FOUNDATIONS',
          'PA-GH-6400-RIGHTS-DAILY-PRACTICE'
        ) then format(
          E'\n\nPause-and-apply for %s: Using a fictional or de-identified shift example, identify the right involved, the person''s communication, any immediate assessed risk, the least intrusive support, and the current plan authority. State who must review a proposed limitation, how the person can complain, one respectful staff phrase, and one objective record entry. A blanket house rule, staff convenience, or an informal supervisor decision does not create authority to restrict a right.',
          v_lesson ->> 'title'
        )
        when v_item ->> 'catalog_code' = 'PA-GH-6400-INCIDENT-RESPONSE' then format(
          E'\n\nPause-and-apply for %s: Use a de-identified event to separate immediate life safety, protection, emergency care, external reporting, Chapter 6400 notification, evidence preservation, and continued support. Write the first three actions in order, the observable facts to communicate, the recipient who confirms each notification, and the handoff owner. Identify one action staff must avoid because it could delay protection, contaminate evidence, or exceed the direct worker''s role.',
          v_lesson ->> 'title'
        )
        when v_item ->> 'catalog_code' = 'PA-GH-6400-INCIDENT-DOCUMENTATION' then format(
          E'\n\nPause-and-apply for %s: Draft a de-identified record that separates observation, exact quote, attributed information, action, notification, and unknown fact. Preserve chronology and the correction trail. Then identify the certified-investigation boundary, one possible system contributor, a corrective action with an owner and due date, and an outcome measure that can show whether recurrence decreased. Do not assign motive, coordinate accounts, backdate, or announce an unverified finding.',
          v_lesson ->> 'title'
        )
        when v_item ->> 'catalog_code' = 'PA-GH-6400-HEALTH-SAFETY' then format(
          E'\n\nPause-and-apply for %s: Build a de-identified shift note with the person''s baseline, exact observed change, time, measurement or direct quote, current individual instruction consulted, action within your training, qualified contact, response received, and reassessment or handoff. Name an emergency sign that bypasses routine supervisor permission and one boundary that prevents staff from diagnosing, changing an order, or improvising a clinical procedure.',
          v_lesson ->> 'title'
        )
        when v_item ->> 'catalog_code' = 'PA-GH-6400-DOCUMENTATION-FUNDS' then format(
          E'\n\nPause-and-apply for %s: Create a de-identified audit trail showing the source fact, time, author, authorized correction, minimum-necessary recipient, and preserved original entry. For money or property, include the person''s choice, amount, receipt, balance, staff assistance, and reconciliation. Identify the notification and containment steps for one discrepancy or disclosure. Never share credentials, pre-chart, conceal a shortage, or replace required reporting with quiet repayment.',
          v_lesson ->> 'title'
        )
        when v_item ->> 'catalog_code' = 'PA-GH-6400-MED-SAFETY-AWARENESS' then format(
          E'\n\nPause-and-apply for %s: Using a fictional medication concern, identify the current order or record to check, the person and medication information to protect, the immediate observation, the qualified medication or clinical contact, instructions received, and the factual entry or correction trail. State what an unqualified worker must not administer, change, hide, or guess. Separate emergency response and awareness duties from the Section 6400.169 qualification required to administer medication.',
          v_lesson ->> 'title'
        )
        when v_item ->> 'catalog_code' = 'PA-GH-6400-EMERGENCY-READINESS' then format(
          E'\n\nPause-and-apply for %s: Use the actual home plan to identify the alarm or warning, first protective action, individual mobility or communication support, staff role, accountability method, emergency contact, relocation threshold, essential medication or equipment need, and handoff record. Name one foreseeable failure and a backup. Do not reenter an unsafe area, improvise beyond training, or treat this general preparation as verified fire-safety or first-aid and CPR credit.',
          v_lesson ->> 'title'
        )
        else ''
      end;
      v_sort := v_sort + 1;
      insert into public.course_blocks (
        course_version_id, organization_id, block_type, sort_order, title, body
      ) values (
        v_version_id, null, 'text', v_sort, v_lesson ->> 'title',
        jsonb_build_object(
          'content', (v_lesson ->> 'content') || v_applied_prompt || v_instruction_prompt,
          'estimated_minutes', (v_lesson ->> 'estimated_minutes')::integer,
          'activity_type', case when v_lesson ->> 'activity_type' = 'practice'
            then 'practice' else 'instruction' end
        )
      );
    end loop;

    for v_scenario in select value from jsonb_array_elements(v_item -> 'scenarios')
    loop
      v_applied_prompt := E'\n\nLearner work product: Write a shift-ready response for this scenario. Identify the first observable fact or cue, immediate protection, ordered actions, the current plan or official procedure to consult, required internal and external notifications, the factual record or confirmation to retain, and the point for qualified escalation. Explain how the response preserves the person''s choice, dignity, privacy, and safety. Include one likely implementation barrier and a practical way to address it without inventing a new restriction, procedure, investigation finding, or credential.';
      v_sort := v_sort + 1;
      insert into public.course_blocks (
        course_version_id, organization_id, block_type, sort_order, title, body
      ) values (
        v_version_id, null, 'text', v_sort, v_scenario ->> 'title',
        jsonb_build_object(
          'content', (v_scenario ->> 'content') || v_applied_prompt,
          'estimated_minutes', (v_scenario ->> 'estimated_minutes')::integer,
          'activity_type', case when v_scenario ->> 'activity_type' = 'practice'
            then 'practice' else 'scenario' end
        )
      );
    end loop;

    v_sort := v_sort + 1;
    insert into public.course_blocks (
      course_version_id, organization_id, block_type, sort_order, title, body
    ) values (
      v_version_id, null, 'text', v_sort, 'Official Sources and Scope Boundary',
      jsonb_build_object(
        'content', v_item ->> 'source_content',
        'estimated_minutes', (v_item ->> 'source_minutes')::integer,
        'activity_type', 'sources'
      )
    );

    v_sort := v_sort + 1;
    insert into public.course_blocks (
      course_version_id, organization_id, block_type, sort_order, title, body
    ) values (
      v_version_id, null, 'quiz', v_sort, 'Final Knowledge Assessment',
      jsonb_build_object(
        'content', 'Complete the final assessment. Review each explanation before retrying.',
        'estimated_minutes', (v_item ->> 'quiz_minutes')::integer,
        'activity_type', 'assessment'
      )
    ) returning id into v_block_id;

    insert into public.quizzes (
      course_block_id, organization_id, title, passing_score_percent, max_attempts
    ) values (
      v_block_id, null, (v_item ->> 'title') || ' Final Assessment', 80, 3
    ) returning id into v_quiz_id;

    v_sort := 0;
    for v_question in select value from jsonb_array_elements(v_item -> 'questions')
    loop
      v_sort := v_sort + 1;
      insert into public.quiz_questions (
        quiz_id, organization_id, question_text, question_type, sort_order, points
      ) values (
        v_quiz_id, null, v_question ->> 'text', 'single_choice', v_sort, 1
      ) returning id into v_question_id;

      insert into public.quiz_question_explanations (question_id, organization_id, explanation)
      values (
        v_question_id,
        null,
        v_question ->> 'explanation'
      );

      v_answer_sort := 0;
      for v_answer in
        select answer_item.value
        from jsonb_array_elements(v_question -> 'answers')
          with ordinality as answer_item(value, ordinality)
        order by mod(
          (answer_item.ordinality::integer - 1) + (v_sort - 1),
          jsonb_array_length(v_question -> 'answers')
        )
      loop
        v_answer_sort := v_answer_sort + 1;
        insert into public.quiz_answers (
          question_id, organization_id, answer_text, is_correct, sort_order
        ) values (
          v_question_id, null, v_answer ->> 'text',
          (v_answer ->> 'correct')::boolean, v_answer_sort
        );
      end loop;
    end loop;

    insert into public.course_compliance_credits (
      course_id, course_version_id, training_type_id, topic_code,
      credit_hours, credit_mode, citation_note
    ) values
      (
        v_course_id, v_version_id, v_direct_type_id, v_item ->> 'topic_code',
        (v_item ->> 'credit_hours')::numeric, 'verified_only',
        (v_item ->> 'citation_note') ||
          ' GH-DIRECT-ANNUAL audience and completion evidence must be verified by the home.'
      ),
      (
        v_course_id, v_version_id, v_other_type_id, v_item ->> 'topic_code',
        (v_item ->> 'credit_hours')::numeric, v_item ->> 'other_mode',
        (v_item ->> 'citation_note') ||
          ' GH-OTHER-ANNUAL applicability and the employee role must be verified by the home.'
      );

    -- The version remains a draft until all blocks, sources, assessment rows,
    -- explanations, answer keys, and regulatory mappings have been inserted.
    perform set_config('app.privileged_write', 'on', true);
    update public.course_versions
    set status = 'published', published_at = now()
    where id = v_version_id;
    update public.courses
    set current_version_id = v_version_id, status = 'published'
    where id = v_course_id;
    perform set_config('app.privileged_write', 'off', true);
  end loop;
end
$migration$;
